INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial do Poder Judiciário', -30.032191, -51.2298532, 'museum', 'O Memorial do Judiciário do Rio Grande do Sul está localizado no térreo do Palácio da Justiça, na Praça Marechal Deodoro, no Centro Histórico de Porto Alegre. Criado em 1998, tem como missão preservar a memória do Poder Judiciário gaúcho. Reúne arquivo histórico, biblioteca, museu com acervo objetal e realiza exposições temáticas de longa e média duração. Promove visitas guiadas ao acervo e ao imponente Palácio da Justiça, ícone da arquitetura modernista. Atendimento gratuito de segunda a sexta, das 12h às 19h.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Pal%C3%A1cio_da_Justi%C3%A7a_Porto_Alegre.jpg/640px-Pal%C3%A1cio_da_Justi%C3%A7a_Porto_Alegre.jpg', NULL, 'https://www.tjrs.jus.br/novo/institucional/o-tjrs/historia/memorial-do-judiciario/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu de Paleontologia Irajá Damiani Pinto', -30.0735274, -51.1208412, 'museum', 'Fundado em 1945 pelo professor Irajá Damiani Pinto, o museu está vinculado ao Instituto de Geociências da UFRGS, no Campus do Vale. Possui um dos mais importantes acervos paleontológicos da América Latina, com mais de 60 mil peças, incluindo fósseis de vertebrados, invertebrados, plantas e microrganismos de todos os períodos geológicos. O foco principal são os vertebrados triássicos do Rio Grande do Sul, de 250 a 200 milhões de anos atrás. Recebe visitas de escolas, pesquisadores e apreciadores da história da vida na Terra.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/Museu_de_Paleontologia_Iraj%C3%A1_Damiani_Pinto_-_UFRGS.jpg/640px-Museu_de_Paleontologia_Iraj%C3%A1_Damiani_Pinto_-_UFRGS.jpg', 'pt:Museu de Paleontologia Irajá Damiani Pinto', 'https://www.ufrgs.br/museupaleonto/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pedra do Pé de Deus', -30.117409, -51.2418065, 'attraction', 'A Pedra do Pé de Deus é uma formação rochosa granítica localizada no Morro do Osso, na zona sul de Porto Alegre. Trata-se de um bloco de pedra com extremidades arredondadas, assentado sobre outras rochas e formando uma pequena caverna em sua parte inferior. O nome vem de uma lenda indígena que atribui à pedra propriedades curativas, ligadas à passagem de uma divindade pelo local. A pedra é um marco cultural e espiritual, especialmente entre os indígenas Kaingang, que reconhecem o Morro do Osso como território ancestral.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Elis Regina', -30.0346517, -51.241332, 'artwork', 'Estátua em bronze em tamanho natural da cantora porto-alegrense Elis Regina (1945–1982), uma das maiores vozes da Música Popular Brasileira. A obra foi criada pelo artista plástico José Pereira Passos e doada à cidade pela Companhia Zaffari. Inaugurada em 26 de março de 2009, no aniversário de 237 anos de Porto Alegre, está localizada na Orla Moacyr Scliar, ao lado da Usina do Gasômetro, de frente para o Guaíba. A base de granito verde e preto remete a um disco de vinil (LP), com estrelas de metal em vários tamanhos.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/31/Elis_Regina_statue_Porto_Alegre.jpg/480px-Elis_Regina_statue_Porto_Alegre.jpg', NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Estrela Guia II', -30.0718528, -51.240134, 'artwork', 'Escultura pública localizada na zona sul de Porto Alegre, próxima ao bairro Cristal. A obra faz parte do conjunto de intervenções artísticas urbanas que ornamentam os espaços públicos da cidade, integrando arte e paisagem à beira do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Mário Quintana e Carlos Drummond de Andrade', -30.0302041, -51.2308718, 'artwork', 'Conjunto escultórico em bronze inaugurado em 26 de outubro de 2001 na Praça da Alfândega, no Centro Histórico de Porto Alegre. Oficialmente intitulado "Monumento à Literatura Brasileira", retrata um encontro imaginário entre os poetas Mário Quintana (sentado ao banco) e Carlos Drummond de Andrade (em pé, com um livro). A obra foi esculpida por Xico Stockinger em coautoria com Eloisa Tregnago, encomendada pela Câmara Riograndense do Livro para a 47ª Feira do Livro de Porto Alegre. Drummond segurava um livro de bronze, furtado em 2015 e restituído em 2022.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Monumento_%C3%A0_Literatura_Brasileira_-_Porto_Alegre.jpg/480px-Monumento_%C3%A0_Literatura_Brasileira_-_Porto_Alegre.jpg', 'pt:Monumento à Literatura Brasileira', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'O Túnel do Túnel', -30.0316665, -51.2194685, 'artwork', 'Obra de arte urbana localizada no Centro Histórico de Porto Alegre. A instalação explora de forma lúdica e conceitual a ideia de profundidade e perspectiva, integrando-se à arquitetura e ao cotidiano da cidade. É uma das intervenções artísticas permanentes que compõem o patrimônio cultural público de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'A Fuga', -30.0292514, -51.2313563, 'artwork', 'Escultura pública integrante do Museu de Percurso do Negro em Porto Alegre, projeto cultural que percorre diferentes pontos da cidade com obras de arte que narram a história e a resistência da comunidade afro-brasileira na capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pegada Africana', -30.0301616, -51.2307524, 'artwork', 'Obra de arte pública integrante do Museu de Percurso do Negro em Porto Alegre, iniciativa que espalha esculturas e instalações pela cidade para contar a história e a presença africana e afro-brasileira em Porto Alegre. A peça evoca a chegada e a marca deixada pela cultura africana na formação da sociedade gaúcha.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Teorema', -30.0293408, -51.2319792, 'artwork', 'Escultura pública localizada na Praça da Alfândega, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que ornamentam os espaços públicos centrais da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'A Samaritana', -30.0296353, -51.2304624, 'artwork', 'Escultura pública localizada no Centro Histórico de Porto Alegre. A obra faz referência à figura bíblica da Samaritana, mulher que ofereceu água a Jesus junto a um poço. A peça integra o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'MERGS', -30.030082, -51.2294122, 'museum', 'O Museu da Eletricidade do Rio Grande do Sul (MERGS) está localizado no Centro Histórico de Porto Alegre. Dedicado à história da energia elétrica no estado, o museu preserva equipamentos, documentos e memórias da evolução do sistema elétrico gaúcho, promovendo educação patrimonial e técnica sobre o setor energético.', NULL, 'pt:Museu da Eletricidade do Rio Grande do Sul', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cono Sul', -30.0544285, -51.2307807, 'artwork', 'Escultura pública em forma de cone localizada próxima ao Largo dos Açorianos, em Porto Alegre. A obra integra o conjunto de monumentos que ornamentam os espaços públicos do Centro Histórico, compondo o cenário artístico e cultural da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torre de Ferro', -30.0480886, -51.2325621, 'artwork', 'Escultura vertical em ferro localizada no Centro Histórico de Porto Alegre. A peça integra o conjunto de obras de arte pública que marcam os espaços urbanos da capital gaúcha, estabelecendo diálogo entre arte, arquitetura e paisagem.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pórtico', -30.0481665, -51.231471, 'artwork', 'Escultura em forma de pórtico localizada no Centro Histórico de Porto Alegre. Obras com essa tipologia são comuns no patrimônio artístico público da cidade, funcionando como marcos visuais que delimitam e qualificam espaços urbanos.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0482458, -51.2296503, 'artwork', 'Escultura pública sem título oficial localizada no Centro Histórico de Porto Alegre, próxima ao Largo dos Açorianos. Integra o conjunto de obras de arte permanentes distribuídas pelos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Canhão', -30.0565144, -51.2311506, 'artwork', 'Canhão histórico exposto como peça de patrimônio público no Centro Histórico de Porto Alegre, próximo ao Largo dos Açorianos. Peças de artilharia antigas são frequentemente preservadas como monumentos históricos, evocando o passado militar e colonial da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0527095, -51.2320786, 'artwork', 'Escultura pública sem título oficial localizada no entorno do Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que enriquecem os espaços públicos da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'El Canto de las Flores', -30.0533763, -51.2309029, 'artwork', 'Escultura pública intitulada "El Canto de las Flores" (O Canto das Flores), localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra celebra a natureza e a beleza floral, integrando o patrimônio artístico permanente dos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Flor', -30.0540508, -51.2303814, 'artwork', 'Escultura representando uma flor, localizada próxima ao Largo dos Açorianos no Centro Histórico de Porto Alegre. Obras com temática floral são recorrentes no patrimônio artístico público da cidade, simbolizando vida e renovação urbana.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Mastro', -30.0563759, -51.2310458, 'artwork', 'Mastro decorativo ou escultura vertical localizada próxima ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte pública e elementos urbanos que compõem a paisagem cultural da região central da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Planos em um Plano', -30.0537926, -51.2304328, 'artwork', 'Escultura pública de caráter abstrato localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra explora relações entre planos e volumes no espaço, integrando o conjunto de intervenções artísticas permanentes dos espaços públicos do Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Rayo', -30.0541885, -51.2304854, 'artwork', 'Escultura pública intitulada "Rayo" (Raio), localizada próxima ao Largo dos Açorianos em Porto Alegre. A forma dinâmica da obra evoca energia e movimento, integrando o conjunto de obras de arte permanentes que ornamentam os espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0541129, -51.2306961, 'artwork', 'Escultura pública sem título oficial localizada próxima ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que enriquecem os espaços públicos centrais da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Paisagem Lunar', -30.0272352, -51.1996941, 'artwork', 'Obra de arte pública intitulada "Paisagem Lunar", localizada no bairro Floresta, em Porto Alegre. A escultura ou instalação evoca a superfície da lua, estabelecendo um diálogo poético entre o espaço urbano e o cosmos, integrando o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Âncora', -30.0564948, -51.2310733, 'artwork', 'Âncora histórica exposta como peça de patrimônio público próximo ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Elementos náuticos como âncoras são frequentemente preservados como monumentos, evocando a história portuária e fluvial da cidade às margens do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cavalo e Cavaleiro', -30.0558338, -51.230855, 'artwork', 'Escultura representando cavalo e cavaleiro, localizada próxima ao Largo dos Açorianos em Porto Alegre. A temática equestre é recorrente no patrimônio artístico gaúcho, remetendo à tradição dos pampas e à figura do gaúcho, símbolo cultural do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Matriz Urbana', -30.0363654, -51.1874249, 'artwork', 'Obra de arte pública intitulada "Matriz Urbana", localizada no bairro Petrópolis, em Porto Alegre. A peça dialoga com os conceitos de estrutura e organização do espaço urbano, integrando o patrimônio artístico público da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Leão de São Marcos', -30.0513786, -51.2294365, 'artwork', 'Escultura representando o Leão de São Marcos, símbolo da República de Veneza, localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra homenageia a herança italiana e veneziana na formação cultural do Rio Grande do Sul, integrando o patrimônio artístico público da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos 100 Anos da Imigração Judaica no RS', -30.0386395, -51.1739162, 'artwork', 'Monumento comemorativo aos 100 anos da imigração judaica no Rio Grande do Sul, localizado no bairro Petrópolis, em Porto Alegre. A obra celebra a contribuição da comunidade judaica para o desenvolvimento cultural, econômico e social do estado gaúcho, reconhecendo a história e a resiliência dos imigrantes e seus descendentes.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria Iberê Camargo', -30.0341205, -51.2414431, 'museum', 'Espaço expositivo vinculado à Fundação Iberê Camargo, dedicado à obra do pintor gaúcho Iberê Camargo (1914–1994), um dos mais importantes artistas plásticos brasileiros do século XX. A Fundação foi criada em 1995 e sua sede atual, projetada pelo arquiteto português Álvaro Siza, foi inaugurada em 2008. O edifício, premiado com o Leão de Ouro na Bienal de Arquitetura de Veneza (2002) e o Mies Crown Hall Americas Prize (2014), é referência arquitetônica internacional. Localizado às margens do Guaíba, é um dos pontos turísticos mais visitados de Porto Alegre.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/76/Funda%C3%A7%C3%A3o_Ib%C3%AAr%C3%AA_Camargo.jpg/640px-Funda%C3%A7%C3%A3o_Ib%C3%AAr%C3%AA_Camargo.jpg', 'pt:Fundação Iberê Camargo', 'https://iberecamargo.org.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria dos Arcos', -30.0340932, -51.2413331, 'museum', 'Espaço cultural localizado no entorno da Fundação Iberê Camargo, na Orla do Guaíba, em Porto Alegre. A galeria integra o conjunto de espaços expositivos da região do bairro Cristal, promovendo artes visuais e intervenções culturais em ambiente privilegiado às margens do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria Lunara', -30.033999, -51.2407678, 'museum', 'Espaço cultural localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba, em Porto Alegre. A Galeria Lunara integra o polo cultural da região do bairro Cristal, oferecendo exposições de artes visuais e atividades culturais em um dos pontos mais belos da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'O Peixe', -30.0329613, -51.2193529, 'artwork', 'Escultura pública representando um peixe, localizada no Centro Histórico de Porto Alegre. A obra integra o patrimônio artístico permanente da cidade, estabelecendo vínculo simbólico com o Guaíba e a tradição fluvial da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu de Geologia', -30.0721923, -51.2278539, 'museum', 'O Museu de Geologia de Porto Alegre, vinculado à Companhia de Pesquisa de Recursos Minerais (CPRM), está localizado no bairro Menino Deus. O museu apresenta coleções de rochas, minerais e fósseis representativos da geologia do Brasil e do mundo, com ênfase no patrimônio geológico do Rio Grande do Sul. É um importante espaço de divulgação científica e educação geocientífica.', NULL, 'pt:Museu de Geologia', 'http://www.cprm.gov.br');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria de Arte do DMAE', -30.0271567, -51.2057402, 'museum', 'Espaço cultural do Departamento Municipal de Água e Esgotos (DMAE) de Porto Alegre, dedicado a exposições de artes visuais. A galeria promove a arte local e regional, disponibilizando seus espaços para artistas gaúchos e nacionais, integrando cultura e serviço público na capital gaúcha.', NULL, NULL, 'http://dmaegaleriadearte.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Bará do Mercado', -30.0274752, -51.2278362, 'artwork', 'Obra de arte pública integrante do Museu de Percurso do Negro em Porto Alegre. Bará (ou Exu Bará) é um orixá da tradição afro-brasileira, guardião das encruzilhadas e dos caminhos. A instalação celebra a espiritualidade e a presença da cultura africana no Mercado Público de Porto Alegre, um dos mais tradicionais do Brasil e historicamente frequentado pela comunidade negra da cidade.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Ruy Tedesco', -30.0666284, -51.2364129, 'museum', 'O Museu Engenheiro Ruy Tedesco está localizado no bairro Menino Deus, em Porto Alegre. Preserva a memória e a obra do engenheiro Ruy Tedesco, figura importante para a história da infraestrutura e do desenvolvimento urbano de Porto Alegre e do Rio Grande do Sul. O museu abriga documentos, projetos e objetos relacionados à trajetória profissional e pessoal do homenageado.', NULL, 'pt:Museu Engenheiro Ruy Tedesco', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Canhão', -30.096657, -51.2576215, 'artwork', 'Canhão histórico exposto no bairro Belém Novo, zona sul de Porto Alegre, próximo ao clube náutico da região. Peças de artilharia antigas são frequentemente preservadas como monumentos históricos em espaços públicos, evocando o passado militar e colonial da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Âncora', -30.0973163, -51.2569357, 'artwork', 'Âncora histórica exposta no bairro Belém Novo, zona sul de Porto Alegre, próximo à orla do Guaíba. Elemento náutico preservado como monumento histórico, evoca a tradição de navegação fluvial na região e a história marítima da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Leonel de Moura Brizola', -30.0338114, -51.2303452, 'artwork', 'Estátua em bronze em tamanho natural do ex-governador e político gaúcho Leonel de Moura Brizola (1922–2004), esculpida pelo artista Otto Dumovich. Inaugurada em janeiro de 2014, está localizada entre a Catedral Metropolitana Madre de Deus e o Palácio Piratini, sede do governo do RS. Brizola foi prefeito de Porto Alegre, governador do RS e do RJ, deputado federal e líder do Movimento da Legalidade em 1961, que resistiu ao golpe militar e garantiu a posse do presidente João Goulart.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Painel Afrobrasileiro', -30.0281542, -51.2271656, 'artwork', 'Painel de arte pública integrante do Museu de Percurso do Negro em Porto Alegre. A obra celebra a cultura afro-brasileira e a contribuição dos povos africanos para a formação da identidade cultural gaúcha, integrando a trajetória histórica da comunidade negra em Porto Alegre.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tambor', -30.0325358, -51.2379039, 'artwork', 'Escultura representando um tambor, integrante do Museu de Percurso do Negro em Porto Alegre. O tambor é um instrumento central nas tradições africanas e afro-brasileiras, presente em rituais religiosos, festas e manifestações culturais. A obra celebra a herança rítmica e espiritual da cultura negra na formação de Porto Alegre.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Nascente do Arroio das Pedras', -30.0381113, -51.1336505, 'attraction', 'Ponto natural de interesse localizado no bairro Lomba do Pinheiro, em Porto Alegre. A nascente do Arroio das Pedras integra a rede hidrográfica da cidade e representa um espaço de valor ambiental, sendo um dos remanescentes de cursos d''água naturais dentro do perímetro urbano de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Arcos de Ipanema', -30.148616, -51.2254416, 'attraction', 'Formação arquitetônica ou estrutura histórica localizada no bairro Ipanema, zona sul de Porto Alegre, às margens do Guaíba. Os arcos integram o patrimônio histórico e paisagístico da região, próximo à orla que oferece belas vistas do lago Guaíba, especialmente ao entardecer.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'turismo nautico', -30.0187561, -51.2566622, 'attraction', 'Ponto de embarque para passeios de barco pelo Guaíba, o lago que margeia Porto Alegre. Os passeios náuticos permitem contemplar a cidade e os pôr do sol do Guaíba sob uma perspectiva única. O Guaíba é um dos mais famosos pelo pôr do sol do mundo, atraindo turistas do Brasil e do exterior.', NULL, NULL, 'https://www.barcoportoalegre10.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Artsom', -29.9983606, -51.1903255, 'artwork', 'Obra de arte pública intitulada "Artsom", localizada no bairro Sarandi, em Porto Alegre. A obra integra o patrimônio artístico permanente da cidade, presente em espaços públicos do extremo norte da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cow Parade Sindicato', -30.0391616, -51.2202084, 'artwork', 'Escultura de vaca decorada integrante da mostra Cow Parade, evento mundial de arte pública que utiliza vacas em escala real como suporte artístico. As obras são criadas por artistas convidados e distribuídas por espaços públicos da cidade. Esta peça está localizada próxima ao sindicato no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Casa de Cultura Mario Quintana', -30.0311314, -51.2345442, 'museum', 'Centro cultural instalado no histórico prédio do Hotel Majestic (construído entre 1916 e 1933, projeto do arquiteto Theodor Wiederspahn), na Rua dos Andradas, 736. Inaugurada em 25 de setembro de 1990, homenageia o poeta porto-alegrense Mário Quintana (1906–1994), que viveu no apartamento 217 do hotel entre 1968 e 1980. O espaço abriga teatros, cinemas, bibliotecas, galerias, os acervos de Elis Regina e Mário Quintana, café com vista para o Guaíba e jardim no terraço. Primeiro grande edifício de Porto Alegre em concreto armado.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d5/Casa_de_Cultura_Mario_Quintana.jpg/640px-Casa_de_Cultura_Mario_Quintana.jpg', 'pt:Casa de Cultura Mario Quintana', 'https://www.ccmq.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Barco Cisne Branco', -30.0256011, -51.2284628, 'attraction', 'O Barco Cisne Branco é um veleiro histórico que realiza passeios turísticos pelo Guaíba, o lago que banha Porto Alegre. Os passeios oferecem uma experiência única de contemplar a cidade, a orla e os famosos pôr do sol do Guaíba a partir da água. É um dos passeios náuticos mais tradicionais e românticos da capital gaúcha.', NULL, NULL, 'https://www.barcocisnebranco.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Arquivo Histórico', -30.0540425, -51.2016508, 'museum', 'O Arquivo Histórico de Porto Alegre Moysés Vellinho, localizado no bairro Azenha, é a principal instituição de guarda e preservação do patrimônio documental do município de Porto Alegre. Fundado em 1959, reúne documentos históricos desde o século XVIII até os dias atuais, incluindo plantas, fotografias, registros municipais e coleções privadas doadas à cidade. É referência para pesquisadores, historiadores e cidadãos interessados na história de Porto Alegre.', NULL, 'pt:Arquivo Histórico de Porto Alegre Moysés Vellinho', 'http://ahpoa.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Restinga', -30.165753, -51.1551364, 'artwork', 'Obra de arte pública localizada no bairro Restinga, zona sul de Porto Alegre. O bairro Restinga é uma das maiores comunidades populares do Brasil e a peça integra o patrimônio artístico e cultural da região, valorizando a identidade local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cavalo de Metal', -30.0354982, -51.1766023, 'artwork', 'Escultura de cavalo em metal localizada no bairro Petrópolis, em Porto Alegre. A figura equestre é símbolo recorrente na cultura gaúcha, evocando os pampas e a tradição pastoril do Rio Grande do Sul. A obra integra o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Garibaldi', -30.0437215, -51.220029, 'attraction', 'Monumento em homenagem a Giuseppe Garibaldi (1807–1882), herói da unificação italiana e figura histórica relevante para o Rio Grande do Sul, onde viveu entre 1837 e 1848 e participou da Revolução Farroupilha. A obra está localizada na Praça Garibaldi, no Centro Histórico de Porto Alegre, reconhecendo a contribuição do "herói de dois mundos" à história gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Gaúcho', -30.0560945, -51.1863552, 'artwork', 'Escultura representando a figura do gaúcho, símbolo cultural do Rio Grande do Sul, localizada no bairro Petrópolis, em Porto Alegre. O gaúcho é o habitante dos pampas sul-rio-grandenses, reconhecido pela sua indumentária típica (pilcha), pelo cavalo, pelo chimarrão e pelas tradições culturais preservadas pelo Movimento Tradicionalista Gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Atlas', -30.0252914, -51.1826331, 'artwork', 'Escultura representando Atlas, o titã da mitologia grega condenado a sustentar o céu sobre os ombros, localizada no bairro Floresta, em Porto Alegre. A figura de Atlas é símbolo de força, resistência e suporte, e a obra integra o patrimônio artístico público da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu das Ilhas', -30.0157427, -51.2609075, 'museum', 'Junto ao CTG Madrugada Campeira (esq. Rua Garruchos)', NULL, NULL, 'https://www.facebook.com/museu-das-ilhas-978206232226945');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Joaquim José Felizardo', -30.0419734, -51.224582, 'museum', 'O Museu de Porto Alegre Joaquim José Felizardo está instalado no Solar Lopo Gonçalves, sobrado histórico construído entre 1845 e 1853 no bairro Cidade Baixa. Fundado em 1979, dedica-se à história e memória de Porto Alegre por meio de três acervos: tridimensional, iconográfico e arqueológico. Homenageia o historiador e criador da Secretaria Municipal de Cultura. O Solar, representativo da arquitetura colonial-neoclássica luso-brasileira, foi tombado como patrimônio histórico em 1979 e é um dos mais belos edifícios históricos da cidade.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Solar_Lopo_Gon%C3%A7alves.jpg/480px-Solar_Lopo_Gon%C3%A7alves.jpg', 'pt:Museu de Porto Alegre Joaquim Felizardo', 'https://www.museudeportoalegre.com/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Expedicionário', -30.0384007, -51.214857, 'artwork', 'Monumento em granito e bronze inaugurado em 16 de julho de 1957 no Parque Farroupilha, em homenagem aos "pracinhas" da Força Expedicionária Brasileira (FEB) que combateram na Segunda Guerra Mundial (1939–1945). Com 17 metros de altura, foi projetado pelo escultor Antônio Caringi (autor também da Estátua do Laçador) e pelo arquiteto Luiz Carlos de Nascimento e Silva. A ideia partiu de uma campanha do jornal Correio do Povo em 1946. O monumento homenageia os três ramos das forças armadas e inclui a alegoria da Bravura (figura feminina em bronze). Também chamado de Arco da Redenção.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Monumento_ao_Expedicion%C3%A1rio_-_Porto_Alegre.jpg/480px-Monumento_ao_Expedicion%C3%A1rio_-_Porto_Alegre.jpg', 'pt:Monumento ao Expedicionário', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Israelita', -30.0325241, -51.2125664, 'museum', 'O Museu Israelita de Porto Alegre está localizado no bairro Bom Fim, região historicamente associada à comunidade judaica da cidade. O museu preserva e divulga a memória, a cultura e a história dos judeus no Rio Grande do Sul, com acervo de objetos rituais, documentos e registros fotográficos da vida comunitária.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Instituto Cultural Judaico Marc Chagal', -30.0324249, -51.2126083, 'museum', 'O Instituto Cultural Judaico Marc Chagall é uma instituição dedicada à preservação e difusão da cultura, história e memória judaica no Rio Grande do Sul. Localizado no bairro Bom Fim, em Porto Alegre, promove exposições, eventos culturais, pesquisas e atividades educativas relacionadas à contribuição judaica para a sociedade gaúcha e brasileira. Homenageia o pintor Marc Chagall (1887–1985), um dos maiores artistas do século XX.', NULL, NULL, 'https://chagall.org.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Travessa dos Venezianos', -30.0421726, -51.222533, 'attraction', 'A Travessa dos Venezianos é um charmoso corredor histórico localizado no bairro Cidade Baixa, em Porto Alegre. O local preserva a memória da comunidade italiana, especialmente dos imigrantes venezianos que se estabeleceram na cidade. A travessa é conhecida por suas fachadas coloridas e atmosfera histórica, sendo um ponto turístico que evoca a herança cultural italiana na capital gaúcha.', NULL, 'pt:Travessa dos Venezianos', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento do Gaúcho Oriental', -30.0371251, -51.2158299, 'artwork', 'Monumento em homenagem ao gaúcho oriental (uruguaio), evocando os laços históricos, culturais e fraternais entre o povo gaúcho do Rio Grande do Sul e o Uruguai. A obra está localizada no Parque Farroupilha, em Porto Alegre, e celebra a identidade compartilhada entre os dois lados da fronteira do Rio da Prata.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Supercuia', -30.0424312, -51.2339418, 'artwork', 'Escultura de grande porte representando uma cuia, o recipiente tradicional utilizado para tomar chimarrão, bebida símbolo da cultura gaúcha. Localizada no bairro Bom Fim, em Porto Alegre, a "Supercuia" é uma obra de arte pública que celebra com humor e monumentalidade um dos ícones mais queridos da identidade cultural do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tributo ao Municipalismo', -30.0494044, -51.2239527, 'artwork', 'Monumento em tributo ao municipalismo, localizado no Centro Histórico de Porto Alegre. A obra celebra a importância do poder local e da autonomia municipal na organização política e social do Brasil, valorizando a democracia e a gestão participativa nas cidades.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Antera', -30.0254791, -51.199585, 'artwork', 'Escultura pública intitulada "Antera", localizada no bairro Floresta, em Porto Alegre. O nome evoca a parte masculina da flor (antera), sugerindo temas de fertilidade, natureza e vida. A obra integra o patrimônio artístico permanente dos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Loureiro da Silva', -30.0314244, -51.2241482, 'artwork', 'Busto ou estátua em homenagem a José Loureiro da Silva (1905–1959), prefeito de Porto Alegre de 1937 a 1943, responsável pela execução de importantes obras de urbanização na cidade, incluindo a abertura da Avenida Farrapos e outras intervenções que modernizaram a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto San Martín', -30.031875, -51.2231892, 'artwork', 'Busto em homenagem ao General José de San Martín (1778–1850), herói da independência da Argentina, Chile e Peru, considerado o "Libertador da América do Sul". A presença deste monumento em Porto Alegre reflete a relação histórica e cultural entre o Brasil e os países do Prata, celebrando a fraternidade sul-americana.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tape Porã', -30.0295183, -51.2234433, 'artwork', 'Obra de arte pública cujo nome em guarani significa "Caminho Bonito" ou "Boa Trilha". A peça integra o patrimônio artístico permanente de Porto Alegre e homenageia a cultura indígena guarani, povo que habitava a região antes da colonização europeia. Localizada no Centro Histórico, a obra convida à reflexão sobre as raízes indígenas da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto do General José Gervasio Artigas', -30.0292681, -51.2303854, 'memorial', 'Busto em homenagem ao General José Gervasio Artigas (1764–1850), herói nacional do Uruguai e figura central na história da Bacia do Prata. Artigas lutou pela autonomia dos povos platinos e é símbolo de liberdade e federalismo. O monumento, localizado no Centro Histórico de Porto Alegre, celebra a fraternidade histórica entre o Rio Grande do Sul e o Uruguai.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Conde de Porto Alegre', -30.0318254, -51.2246249, 'monument', 'Monumento em homenagem ao Marechal Manuel Marques de Sousa, Conde de Porto Alegre (1804–1875), militar gaúcho que participou da Guerra do Paraguai, da Revolução Farroupilha e de outros conflitos do Império Brasileiro. O Conde de Porto Alegre é um dos mais importantes personagens militares da história do Rio Grande do Sul e da cidade que leva seu título nobiliárquico.', NULL, 'pt:Monumento ao Conde de Porto Alegre', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a José Loureiro da Silva', -30.0373227, -51.2377061, 'memorial', 'Monumento em homenagem a José Loureiro da Silva (1905–1959), prefeito de Porto Alegre entre 1937 e 1943 (e novamente de 1952 a 1953). Durante sua gestão, foi responsável por importantes obras de urbanização, como a abertura da Avenida Farrapos, a construção do Viaduto Otávio Rocha e a modernização do sistema viário da cidade. Localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Zumbi dos Palmares', -30.0379097, -51.2269822, 'monument', 'Monumento em homenagem a Zumbi dos Palmares (1655–1695), líder do Quilombo dos Palmares, maior reduto de resistência negra da história colonial brasileira, localizado em Alagoas. Zumbi é símbolo de resistência à escravidão e herói nacional afro-brasileiro. O dia 20 de novembro, data de sua morte, é o Dia da Consciência Negra. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Antônio Carlos Lopes', -30.0295366, -51.2314736, 'memorial', 'Herma (busto sobre pilastra) em homenagem a Antônio Carlos Lopes, personalidade ligada à cultura e à imprensa porto-alegrense. Localizada no Centro Histórico de Porto Alegre, a peça integra o conjunto de homenagens a personagens relevantes da história da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Caldas Júnior', -30.030248, -51.231177, 'memorial', 'Herma em homenagem a Caldas Júnior (1868–1913), fundador do Correio do Povo, o mais antigo jornal em circulação no Rio Grande do Sul, fundado em 1895. Caldas Júnior foi uma figura central para a imprensa gaúcha e para a vida cultural de Porto Alegre no início do século XX. A herma está localizada no Centro Histórico da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Francisco de Leonardo Truda', -30.0299934, -51.2304567, 'memorial', 'Herma em homenagem a Francisco de Leonardo Truda (1878–1942), jornalista, escritor e intelectual gaúcho que exerceu grande influência na vida cultural e política do Rio Grande do Sul no início do século XX. Truda foi diretor do Correio do Povo e colaborou com diversas publicações da época.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma ao Barão de Santo Ângelo', -30.0300469, -51.2310464, 'memorial', 'Herma em homenagem ao Barão de Santo Ângelo, título nobiliárquico do Império Brasileiro relacionado à cidade de Santo Ângelo, no Rio Grande do Sul. O monumento está localizado no Centro Histórico de Porto Alegre e integra o conjunto de homenagens a figuras históricas relevantes para o estado gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a José Bertaso', -30.0301308, -51.2308168, 'memorial', 'Monumento em homenagem a José Bertaso, empresário e fundador da Livraria do Globo, uma das mais importantes editoras e livrarias da história cultural do Rio Grande do Sul. A Livraria do Globo, fundada em Porto Alegre no final do século XIX, publicou obras de grandes escritores brasileiros e foi um centro cultural fundamental para o Sul do Brasil.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de João Cândido', -30.0516709, -51.2300329, 'memorial', 'Busto em homenagem a João Cândido Felisberto (1880–1969), o "Almirante Negro", líder da Revolta da Chibata de 1910, movimento que aboliu os castigos corporais na Marinha Brasileira. João Cândido nasceu em Santo Antônio da Patrulha (RS) e é símbolo da resistência negra no Brasil. O busto está localizado próximo ao Largo dos Açorianos, no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto do Almirante Marquês de Tamandaré', -30.0565145, -51.2310993, 'memorial', 'Busto em homenagem ao Almirante Joaquim Marques Lisboa, Marquês de Tamandaré (1807–1897), patrono da Marinha Brasileira e um dos maiores heróis navais da história do Brasil. Natural de Rio Grande (RS), Tamandaré participou de diversas batalhas navais, incluindo a Guerra do Paraguai. O busto está localizado próximo ao Largo dos Açorianos.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Plácido de Castro', -30.0566813, -51.2317952, 'memorial', 'Monumento em homenagem a José Plácido de Castro (1873–1908), militar gaúcho que liderou a Revolução Acreana (1902–1903), movimento que resultou na incorporação do Acre ao território brasileiro. Plácido de Castro é herói nacional e símbolo do expansionismo territorial brasileiro. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torre de Ferro', -30.0480886, -51.2325621, 'artwork', 'Escultura vertical em ferro localizada no Centro Histórico de Porto Alegre. A peça integra o conjunto de obras de arte pública que marcam os espaços urbanos da capital gaúcha, estabelecendo diálogo entre arte, arquitetura e paisagem.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Manoel Raimundo Soares', -30.0503832, -51.2323, 'memorial', 'Monumento em homenagem a Manoel Raimundo Soares (1939–1966), militante político gaúcho assassinado durante a ditadura militar brasileira (1964–1985). Soares foi preso, torturado e morto pelos agentes do regime. Seu corpo, com as mãos atadas, foi encontrado boiando no Rio Jacuí, sendo chamado de "O Anjo das Pernas Tortas". O monumento está localizado no Centro Histórico de Porto Alegre e é um símbolo da resistência democrática.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Centenário da Imigração Judaica', -30.0359385, -51.2110474, 'monument', 'Monumento comemorativo ao centenário da imigração judaica no Rio Grande do Sul, localizado no bairro Bom Fim, em Porto Alegre. A obra celebra a chegada dos primeiros imigrantes judeus ao estado, sua contribuição para o desenvolvimento econômico, cultural e social do RS e a formação de uma das mais expressivas comunidades judaicas do Brasil.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Santos Dumont', -30.0381602, -51.2149518, 'memorial', 'Memorial ou busto em homenagem a Alberto Santos Dumont (1873–1932), inventor brasileiro considerado por muitos o "Pai da Aviação". Santos Dumont realizou o histórico voo do 14-Bis em Paris, em 1906, e é patrono da Aeronáutica Brasileira. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Marco da Carris', -30.0347311, -51.2220535, 'monument', 'Marco histórico em homenagem à CARRIS (Companhia Carris Porto-Alegrense), empresa responsável pelo transporte público de bondes e ônibus em Porto Alegre. Os bondes elétricos circularam pela cidade de 1908 a 1970, sendo um dos sistemas de transporte mais importantes da história urbana da capital gaúcha. O marco está localizado no Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Lions Clube Balneários', -30.1040315, -51.2530188, 'memorial', 'Monumento doado pelo Lions Clube Balneários à cidade de Porto Alegre, localizado na zona sul da capital. O Lions Club International é uma organização humanitária mundial dedicada ao serviço comunitário, e os monumentos doados pelos clubes locais marcam o compromisso com a comunidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Ano Internacional da Criança', -30.0278356, -51.201574, 'memorial', 'Monumento em comemoração ao Ano Internacional da Criança, proclamado pela ONU em 1979, que marcou o 20º aniversário da Declaração dos Direitos da Criança. A obra está localizada no bairro Floresta, em Porto Alegre, e celebra os direitos, a proteção e o bem-estar das crianças.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Lions Clube Independência', -30.0278679, -51.2003229, 'memorial', 'Monumento doado pelo Lions Clube Independência à cidade de Porto Alegre. Localizado no bairro Floresta, o monumento marca a contribuição da filial local do Lions Club International às ações comunitárias e humanitárias na capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Johann Wolfgang von Goethe', -30.0283958, -51.2003725, 'memorial', 'Monumento em homenagem a Johann Wolfgang von Goethe (1749–1832), o maior escritor da língua alemã e um dos maiores da literatura universal. Autor do "Fausto" e de "Os Sofrimentos do Jovem Werther", Goethe exerceu influência profunda na cultura ocidental. O monumento está localizado no bairro Floresta, em Porto Alegre, e homenageia a forte herança cultural alemã no Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Rotary Club', -30.0282175, -51.2008042, 'memorial', 'Monumento doado pelo Rotary Club à cidade de Porto Alegre, localizado no bairro Floresta. O Rotary International é uma das maiores organizações humanitárias do mundo, e este monumento marca a presença e a contribuição do clube local às ações comunitárias da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Maurício Sirotsky Sobrinho', -30.0397023, -51.237552, 'memorial', 'Busto em homenagem a Maurício Sirotsky Sobrinho (1931–1990), empresário gaúcho e fundador do Grupo RBS (Rede Brasil Sul de Comunicações), maior conglomerado de mídia do Sul do Brasil. Sirotsky foi uma figura central para o desenvolvimento da comunicação e da cultura no Rio Grande do Sul. O busto está localizado próximo à Orla do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a José Antônio Daudt', -30.0266226, -51.2013906, 'memorial', 'Memorial em homenagem a José Antônio Daudt, personalidade ligada à história política e administrativa de Porto Alegre. O memorial está localizado no bairro Floresta, integrando o conjunto de homenagens a personagens relevantes da história da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Rotary Club de Porto Alegre Norte', -30.0251712, -51.2012585, 'memorial', 'Memorial em homenagem ao Rotary Club de Porto Alegre Norte, reconhecendo a atuação humanitária e comunitária do clube na região norte da capital gaúcha. Localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Taxistas Mortos em Serviço', -30.0423798, -51.2333608, 'memorial', 'Memorial em homenagem aos taxistas que perderam a vida em serviço na cidade de Porto Alegre. A obra presta tributo aos profissionais do transporte individual que foram vítimas de violência ou acidentes no exercício de sua profissão, reconhecendo os riscos enfrentados cotidianamente por esses trabalhadores.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pedra da Memória', -30.0396429, -51.2378081, 'memorial', 'Memorial em forma de pedra localizado próximo à Orla do Guaíba, em Porto Alegre. A "Pedra da Memória" é um espaço de recordação e homenagem a pessoas ou eventos, integrando o patrimônio memorialístico da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento Gaúcho Oriental', -30.0348541, -51.2206334, 'monument', 'Monumento em homenagem ao gaúcho oriental (uruguaio), celebrando os laços históricos e culturais entre o povo gaúcho do Rio Grande do Sul e o Uruguai. A obra está localizada no Centro Histórico de Porto Alegre e evoca a identidade compartilhada entre as duas margens do Rio da Prata.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Centenário de Nascimento do Deputado Carlos Santos', -30.0436946, -51.2042676, 'memorial', 'Memorial comemorativo ao centenário de nascimento do Deputado Carlos Santos, político gaúcho que teve atuação relevante na história legislativa do Rio Grande do Sul. O memorial está localizado no bairro Azenha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao PM Valdeci de Abreu Lopes', -30.0428553, -51.2042113, 'memorial', 'Memorial em homenagem ao policial militar Valdeci de Abreu Lopes, morto em serviço na cidade de Porto Alegre. O memorial presta tributo ao sacrifício dos agentes de segurança pública que perderam a vida no cumprimento do dever de proteger a comunidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Rotary Club de Porto Alegre Norte', -30.0294291, -51.2008077, 'monument', 'Monumento doado pelo Rotary Club de Porto Alegre Norte à cidade, reconhecendo a atuação humanitária e comunitária da organização na região norte da capital gaúcha. Localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Coluna Israelita', -30.0336457, -51.2160712, 'monument', 'Coluna comemorativa da comunidade judaica de Porto Alegre, localizada no bairro Bom Fim, região historicamente associada à comunidade israelita da cidade. A coluna homenageia a contribuição dos imigrantes judeus e seus descendentes para o desenvolvimento cultural, econômico e social de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Carlos Gomes', -30.0350054, -51.2140092, 'monument', 'Busto em homenagem a Antônio Carlos Gomes (1836–1896), compositor brasileiro considerado o maior ópera do século XIX nas Américas. Sua obra mais famosa, "O Guarani" (1870), foi apresentada com grande sucesso no Teatro alla Scala de Milão. O busto está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Chopin', -30.0347287, -51.2139578, 'monument', 'Busto em homenagem a Frédéric Chopin (1810–1849), pianista e compositor polonês, um dos maiores músicos românticos da história. Suas obras para piano solo são consideradas entre as mais expressivas da literatura musical. O busto está localizado no Parque Farroupilha, em Porto Alegre, integrando o conjunto de homenagens a músicos universais presentes no parque.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Beethoven', -30.0347697, -51.213872, 'monument', 'Monumento em homenagem a Ludwig van Beethoven (1770–1827), compositor alemão considerado um dos maiores gênios da história da música ocidental. Suas nove sinfonias, seus concertos para piano e suas sonatas são obras-primas da humanidade. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Obelisco à Comunidade Sírio-Libanesa', -30.0354607, -51.2177687, 'monument', 'Obelisco em homenagem à comunidade sírio-libanesa de Porto Alegre, localizado no Parque Farroupilha. A imigração síria e libanesa para o Rio Grande do Sul, iniciada no final do século XIX, trouxe importantes contribuições para o comércio, a cultura e a gastronomia da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Imperatriz Leopoldina', -30.0347791, -51.220929, 'monument', 'Monumento em homenagem à Imperatriz Maria Leopoldina da Áustria (1797–1826), primeira imperatriz do Brasil e esposa de Dom Pedro I. Leopoldina desempenhou papel fundamental na Independência do Brasil em 1822, sendo uma das mais importantes figuras femininas da história brasileira. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torii', -30.0356375, -51.2157841, 'monument', 'Torii é um portão tradicional japonês que marca a entrada de um santuário xintoísta. O torii presente no Parque Farroupilha, em Porto Alegre, foi doado pela comunidade japonesa e homenageia a imigração nipônica no Rio Grande do Sul. É um símbolo da diversidade cultural que caracteriza a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Fundadores do Veleiros do Sul', -30.0966733, -51.2575772, 'memorial', 'Memorial em homenagem aos fundadores do Veleiros do Sul, clube náutico localizado no bairro Belém Novo, zona sul de Porto Alegre, às margens do Guaíba. O clube é uma das mais tradicionais associações de vela do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Comodoro Jorge Bertschinger', -30.0969104, -51.2568917, 'memorial', 'Monumento em homenagem ao Comodoro Jorge Bertschinger, personalidade relevante para o esporte náutico e a história do iatismo no Rio Grande do Sul. O memorial está localizado no bairro Belém Novo, próximo ao Veleiros do Sul, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Tamandaré', -30.0955567, -51.2562098, 'memorial', 'Monumento em homenagem ao Almirante Joaquim Marques Lisboa, Marquês de Tamandaré (1807–1897), patrono da Marinha Brasileira. Natural de Rio Grande (RS), Tamandaré é o maior herói naval da história brasileira, tendo participado de batalhas na Guerra do Paraguai e outros conflitos. O monumento está localizado no bairro Belém Novo, próximo à marina local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem à Imigração Alemã no Brasil', -30.0237338, -51.1565299, 'memorial', 'Memorial em homenagem à imigração alemã no Brasil, localizado no bairro Sarandi, em Porto Alegre. Os imigrantes alemães chegaram ao Rio Grande do Sul a partir de 1824, sendo São Leopoldo (RS) o primeiro polo de colonização germânica. A imigração alemã moldou profundamente a cultura, a arquitetura, a gastronomia e a economia do estado gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Estátua de Fernandão', -30.0669412, -51.2364426, 'memorial', 'Estátua em homenagem a Fernando Luís Rosa, o "Fernandão" (1978–2014), atacante gaúcho que jogou no Grêmio e na seleção brasileira. Considerado ídolo do clube tricolor, Fernandão faleceu tragicamente em um acidente de helicóptero. A estátua está localizada próxima ao Estádio Olímpico Monumental, no bairro Menino Deus.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Almirante Tamandaré', -30.0416282, -51.1824233, 'memorial', 'Memorial em homenagem ao Almirante Tamandaré, patrono da Marinha Brasileira, localizado no bairro Petrópolis, em Porto Alegre. A homenagem reconhece a importância de Tamandaré para a história naval do Brasil e seu legado como figura exemplar das Forças Armadas brasileiras.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial Empresa de Onibus Belem', -30.2098055, -51.1883893, 'memorial', 'Memorial da Empresa de Ônibus Belém, localizado no bairro Belém Novo, zona sul de Porto Alegre. O memorial preserva a história e a tradição da viação Belém, uma das transportadoras de passageiros que contribuiu para a mobilidade urbana na região sul da capital gaúcha.', NULL, NULL, 'http://www.viacaobelemnovo.com.br');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Grêmio FBPA', -30.0286543, -51.2006294, 'monument', 'Monumento em homenagem ao Grêmio Foot-Ball Porto Alegrense (GBPA), fundado em 15 de setembro de 1903, um dos maiores clubes de futebol do Brasil. O Grêmio é tricampeão mundial (1983, 1983 Intercontinental e Copa Libertadores múltiplas vezes) e ídolo da torcida gaúcha. O monumento está localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial Olímpico', -30.0092693, -51.1883565, 'memorial', 'O Memorial Olímpico de Porto Alegre está localizado no bairro Sarandi e homenageia os atletas gaúchos que representaram o Brasil nos Jogos Olímpicos. O Rio Grande do Sul tem uma longa tradição esportiva olímpica, com atletas de destaque em diversas modalidades. O memorial celebra o esforço, a dedicação e as conquistas dos esportistas gaúchos no cenário internacional.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Panteão dos Laureados', -30.0094113, -51.1881564, 'memorial', 'O Panteão dos Laureados, localizado no bairro Sarandi, em Porto Alegre, presta homenagem aos atletas gaúchos que conquistaram medalhas em competições olímpicas e internacionais. O espaço integra o conjunto de memórias esportivas da capital gaúcha e celebra as conquistas dos esportistas do Rio Grande do Sul no cenário mundial.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a João Goulart', -30.0365573, -51.240995, 'memorial', 'Memorial em homenagem a João Goulart (1919–1976), o "Jango", presidente do Brasil de 1961 a 1964 e figura central da história política gaúcha. Goulart foi deposto pelo golpe militar de 1964 e viveu no exílio até a abertura política. Natural de São Borja (RS), é símbolo do trabalhismo e da democracia no Brasil. O memorial está localizado próximo à Orla do Guaíba, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Duque de Caxias', -30.0381971, -51.2150185, 'memorial', 'Memorial ou busto em homenagem ao Marechal Luís Alves de Lima e Silva, Duque de Caxias (1803–1880), patrono do Exército Brasileiro e considerado o maior herói militar da história do Brasil. Caxias participou de diversas guerras e pacificações, sendo símbolo de lealdade e bravura. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Almirante Tamandaré', -30.0382411, -51.2150922, 'memorial', 'Memorial em homenagem ao Almirante Tamandaré, patrono da Marinha Brasileira, localizado no Parque Farroupilha, em Porto Alegre. Natural de Rio Grande (RS), o Marquês de Tamandaré é o maior herói naval do Brasil, símbolo de coragem e patriotismo das Forças Armadas brasileiras.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Povo Cigano', -30.0282668, -51.2004831, 'memorial', 'Memorial em homenagem ao Povo Cigano, localizado no bairro Floresta, em Porto Alegre. A obra reconhece a presença e a contribuição da comunidade cigana na formação cultural do Brasil e do Rio Grande do Sul, celebrando a diversidade étnica e cultural da nação.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Mosaico Rosa dos Ventos', -29.9910528, -51.1843292, 'memorial', 'Mosaico em forma de rosa dos ventos localizado no bairro Sarandi, em Porto Alegre. A rosa dos ventos é símbolo de orientação e navegação, evocando os quatro pontos cardeais. O mosaico integra o patrimônio artístico público da região norte da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pórtico da UFRGS Campus do Vale', -30.0762526, -51.1248862, 'monument', 'Pórtico de entrada do Campus do Vale da Universidade Federal do Rio Grande do Sul (UFRGS), localizado no bairro Agronomia. A UFRGS é a maior e mais importante universidade federal do Sul do Brasil, fundada em 1895. O Campus do Vale abriga institutos de ciências exatas, biológicas e tecnológicas, além de importantes museus universitários. O pórtico marca a entrada principal do campus.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Servidores Municipais', -30.0346915, -51.2413474, 'memorial', 'Memorial em homenagem aos servidores municipais de Porto Alegre, localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba. A obra reconhece a dedicação e o trabalho dos funcionários públicos municipais que contribuem para o funcionamento e o desenvolvimento da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Bonde', -30.0415008, -51.2235705, 'memorial', 'Memorial preservando um bonde histórico, evocando a era dos bondes elétricos em Porto Alegre, que circularam pela cidade de 1908 a 1970. Os bondes foram o principal meio de transporte coletivo da capital gaúcha por décadas, e sua memória é preservada como patrimônio cultural da cidade. O memorial está localizado no Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Escultura de Pedro Rocha', -30.0294116, -51.2013109, 'monument', 'Escultura em homenagem a Pedro Rocha, ex-jogador do Grêmio. Autores: Mario Cladera e Vinicius Vieira.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Símbolo da luta contra a violência no trânsito', -30.0609262, -51.2106216, 'monument', 'Monumento simbólico de conscientização sobre a violência no trânsito, localizado no bairro Menino Deus, em Porto Alegre. A obra integra as ações de educação para o trânsito da cidade, alertando para os riscos da imprudência nas ruas e prestando homenagem às vítimas de acidentes.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'super tinga', -30.1531856, -51.1358503, 'monument', 'Monumento em homenagem a Tinga, nome popular de Célio Fernando Soares Rodrigues, ídolo do futebol gaúcho. Localizado no bairro Belém Novo, na zona sul de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Garibaldi', -30.0437215, -51.220029, 'attraction', 'Monumento em homenagem a Giuseppe Garibaldi (1807–1882), herói da unificação italiana e figura histórica relevante para o Rio Grande do Sul, onde viveu entre 1837 e 1848 e participou da Revolução Farroupilha. Localizado na Praça Garibaldi, no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto Júlio de Castilhos', -30.0287979, -51.2083878, 'memorial', 'Busto em homenagem a Júlio Prates de Castilhos (1860–1903), político positivista gaúcho que foi presidente do Rio Grande do Sul de 1893 a 1898. Castilhos foi figura central na consolidação da República no RS e foi o grande mentor de Borges de Medeiros. O bairro Júlio de Castilhos e o Museu Júlio de Castilhos levam seu nome. O busto está localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Fernando Chagas Riet', -30.0561634, -51.2223142, 'memorial', 'Memorial em homenagem a Fernando Chagas Riet, personalidade ligada à história do esporte ou da cultura em Porto Alegre. O memorial está localizado no bairro Cidade Baixa, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Marechal Mascarenhas de Moraes', -30.0381144, -51.2148254, 'memorial', 'Memorial em homenagem ao Marechal João Batista Mascarenhas de Moraes (1883–1968), comandante da Força Expedicionária Brasileira (FEB) na Segunda Guerra Mundial, na campanha da Itália (1944–1945). Natural de Passo Fundo (RS), Mascarenhas de Moraes é um dos maiores heróis militares gaúchos. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Dr. José Faibes Lubianca', -30.0363591, -51.2103382, 'memorial', 'Memorial em homenagem ao Dr. José Faibes Lubianca, médico e personalidade relevante para a história da saúde pública em Porto Alegre. O memorial está localizado no bairro Bom Fim, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Oswaldo Vergara', -30.0325184, -51.2298651, 'memorial', 'Memorial em homenagem a Oswaldo Vergara (1886–1975), advogado, político e figura proeminente da vida pública gaúcha. Vergara foi presidente do Partido Trabalhista Brasileiro (PTB) no RS e colaborador próximo de Getúlio Vargas. O memorial está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Professor André Leão Puente', -30.0329268, -51.2298377, 'memorial', 'Memorial em homenagem ao Professor André Leão Puente, educador relevante na história da instrução pública em Porto Alegre. O memorial está localizado no Centro Histórico da cidade, reconhecendo a contribuição do homenageado para a educação gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Desiderio Finamor', -30.0569388, -51.2224875, 'memorial', 'Memorial em homenagem a Desiderio Finamor, personalidade ligada à história política ou cultural de Porto Alegre. O memorial está localizado no bairro Cidade Baixa.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'DC-3', -29.9957118, -51.1868187, 'memorial', 'Aeronave histórica Douglas DC-3, preservada como memorial no bairro Sarandi, em Porto Alegre. O DC-3 foi um dos aviões mais importantes da história da aviação civil e militar mundial, produzido entre 1936 e 1942. Muitos exemplares serviram no Brasil, inclusive no Rio Grande do Sul. A aeronave exposta é um símbolo do desenvolvimento da aviação nacional.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Imagem religiosa', -30.1910421, -51.0368067, 'monument', 'Imagem religiosa localizada na zona rural de Porto Alegre, próxima ao bairro Lami. Capelas e imagens de santos são comuns na paisagem rural gaúcha, marcando a devoção religiosa das comunidades de origem europeia que colonizaram a região.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Batalhão Suez', -30.038453, -51.2300938, 'monument', 'Monumento inaugurado em 8 de janeiro de 2016 na Praça dos Açorianos, em homenagem aos soldados gaúchos que integraram o Batalhão Suez, participando das missões de paz da ONU no Oriente Médio entre 1957 e 1967. O Brasil enviou 20 contingentes do Exército ao Canal de Suez, compondo a Força de Emergência das Nações Unidas (UNEF I). A estrutura piramidal em granito, com globo e capacete azul no topo, homenageia os cerca de 700 gaúchos do 5º, 13º e 20º contingentes.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Monumento_ao_Batalhao_Suez_-_Porto_Alegre.jpg/480px-Monumento_ao_Batalhao_Suez_-_Porto_Alegre.jpg', 'pt:Monumento ao Batalhão Suez', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento aos Açorianos', -30.0390289, -51.2295676, 'monument', 'Monumento inaugurado em 26 de março de 1974, aniversário de Porto Alegre, em homenagem à chegada dos primeiros 60 casais açorianos que fundaram a cidade em 1752. A obra do escultor Carlos Tenius, com 17 m de altura e 24 m de comprimento, é feita em aço e evoca uma caravela composta de corpos humanos entrelaçados, tendo à frente uma figura alada (inspirada em Ícaro) que representa a vitória. Localizada no Largo dos Açorianos, próximo ao Centro Administrativo do Estado. Restaurada entre 2016 e 2019.', 'https://upload.wikimedia.org/wikipedia/commons/2/29/Largo_dos_a%C3%A7orianos_2.jpg', 'pt:Monumento aos Açorianos', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torii', -30.03567, -51.2157882, 'monument', 'Torii é um portão tradicional japonês que marca a entrada de um santuário xintoísta. O torii presente no Parque Farroupilha, em Porto Alegre, foi doado pela comunidade japonesa e homenageia a imigração nipônica no Rio Grande do Sul. É um símbolo da diversidade cultural que caracteriza a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Nicolau Copérnico', -30.0438357, -51.2076519, 'memorial', 'Memorial em homenagem a Nicolau Copérnico (1473–1543), astrônomo polonês que formulou o modelo heliocêntrico do Sistema Solar, revolucionando a astronomia e o pensamento científico. O monumento está localizado no bairro Azenha, em Porto Alegre, e homenageia a herança cultural polonesa no Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Annes Dias', -30.0368893, -51.2193317, 'monument', 'Monumento em homenagem ao Dr. Annes Dias (1875–1941), médico sanitarista gaúcho de grande importância para a saúde pública no Rio Grande do Sul e no Brasil. Annes Dias combateu doenças como a varíola e outras endemias, contribuindo decisivamente para a melhoria das condições sanitárias da população gaúcha no início do século XX.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Samuel Hahnemann', -30.0378556, -51.2185464, 'monument', 'Monumento em homenagem a Samuel Hahnemann (1755–1843), médico alemão fundador da homeopatia. A homeopatia foi amplamente difundida no Rio Grande do Sul por imigrantes alemães no século XIX. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Licino Cardoso', -30.0372338, -51.2190873, 'monument', 'Monumento em homenagem a Licínio Cardoso, intelectual e filósofo brasileiro do início do século XX, expoente do positivismo no Brasil. O Positivismo de Auguste Comte foi fortemente influente no Rio Grande do Sul, moldando a política e a cultura gaúcha na Primeira República. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial às Vítimas da COVID-19', -30.0560132, -51.2313612, 'memorial', 'Memorial em homenagem às vítimas da pandemia de COVID-19 em Porto Alegre. Inaugurado após a crise sanitária que assolou o Brasil e o mundo a partir de 2020, o memorial preserva a memória dos que perderam a vida para a doença e homenageia os profissionais de saúde que lutaram para salvar vidas. Localizado no Centro Histórico da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Padre Paulo de Nadal', -30.0483596, -51.2171512, 'memorial', 'Memorial em homenagem ao Padre Paulo de Nadal, religioso que teve atuação relevante na vida comunitária e social de Porto Alegre. O memorial está localizado no bairro Cidade Baixa, reconhecendo a contribuição do sacerdote para a comunidade local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria de Arte do DMAE', -30.0271567, -51.2057402, 'museum', 'Espaço cultural do Departamento Municipal de Água e Esgotos (DMAE) de Porto Alegre, dedicado a exposições de artes visuais. A galeria promove a arte local e regional, disponibilizando seus espaços para artistas gaúchos e nacionais, integrando cultura e serviço público na capital gaúcha.', NULL, NULL, 'http://dmaegaleriadearte.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial do Poder Judiciário', -30.032191, -51.2298532, 'museum', 'O Memorial do Judiciário do Rio Grande do Sul está localizado no térreo do Palácio da Justiça, na Praça Marechal Deodoro, no Centro Histórico de Porto Alegre. Criado em 1998, tem como missão preservar a memória do Poder Judiciário gaúcho. Reúne arquivo histórico, biblioteca, museu com acervo objetal e realiza exposições temáticas de longa e média duração. Promove visitas guiadas ao acervo e ao imponente Palácio da Justiça, ícone da arquitetura modernista. Atendimento gratuito de segunda a sexta, das 12h às 19h.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4e/Pal%C3%A1cio_da_Justi%C3%A7a_Porto_Alegre.jpg/640px-Pal%C3%A1cio_da_Justi%C3%A7a_Porto_Alegre.jpg', NULL, 'https://www.tjrs.jus.br/novo/institucional/o-tjrs/historia/memorial-do-judiciario/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu de Paleontologia Irajá Damiani Pinto', -30.0735274, -51.1208412, 'museum', 'Fundado em 1945 pelo professor Irajá Damiani Pinto, o museu está vinculado ao Instituto de Geociências da UFRGS, no Campus do Vale. Possui um dos mais importantes acervos paleontológicos da América Latina, com mais de 60 mil peças, incluindo fósseis de vertebrados, invertebrados, plantas e microrganismos de todos os períodos geológicos. O foco principal são os vertebrados triássicos do Rio Grande do Sul, de 250 a 200 milhões de anos atrás. Recebe visitas de escolas, pesquisadores e apreciadores da história da vida na Terra.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2e/Museu_de_Paleontologia_Iraj%C3%A1_Damiani_Pinto_-_UFRGS.jpg/640px-Museu_de_Paleontologia_Iraj%C3%A1_Damiani_Pinto_-_UFRGS.jpg', 'pt:Museu de Paleontologia Irajá Damiani Pinto', 'https://www.ufrgs.br/museupaleonto/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pedra do Pé de Deus', -30.117409, -51.2418065, 'attraction', 'A Pedra do Pé de Deus é uma formação rochosa granítica localizada no Morro do Osso, na zona sul de Porto Alegre. Trata-se de um bloco de pedra com extremidades arredondadas, assentado sobre outras rochas e formando uma pequena caverna em sua parte inferior. O nome vem de uma lenda indígena que atribui à pedra propriedades curativas, ligadas à passagem de uma divindade pelo local. A pedra é um marco cultural e espiritual, especialmente entre os indígenas Kaingang, que reconhecem o Morro do Osso como território ancestral.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Elis Regina', -30.0346517, -51.241332, 'artwork', 'Estátua em bronze em tamanho natural da cantora porto-alegrense Elis Regina (1945–1982), uma das maiores vozes da Música Popular Brasileira. A obra foi criada pelo artista plástico José Pereira Passos e doada à cidade pela Companhia Zaffari. Inaugurada em 26 de março de 2009, no aniversário de 237 anos de Porto Alegre, está localizada na Orla Moacyr Scliar, ao lado da Usina do Gasômetro, de frente para o Guaíba. A base de granito verde e preto remete a um disco de vinil (LP), com estrelas de metal em vários tamanhos.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/3/31/Elis_Regina_statue_Porto_Alegre.jpg/480px-Elis_Regina_statue_Porto_Alegre.jpg', NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Estrela Guia II', -30.0718528, -51.240134, 'artwork', 'Escultura pública localizada na zona sul de Porto Alegre, próxima ao bairro Cristal. A obra faz parte do conjunto de intervenções artísticas urbanas que ornamentam os espaços públicos da cidade, integrando arte e paisagem à beira do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Mário Quintana e Carlos Drummond de Andrade', -30.0302041, -51.2308718, 'artwork', 'Conjunto escultórico em bronze inaugurado em 26 de outubro de 2001 na Praça da Alfândega, no Centro Histórico de Porto Alegre. Oficialmente intitulado "Monumento à Literatura Brasileira", retrata um encontro imaginário entre os poetas Mário Quintana (sentado ao banco) e Carlos Drummond de Andrade (em pé, com um livro). A obra foi esculpida por Xico Stockinger em coautoria com Eloisa Tregnago, encomendada pela Câmara Riograndense do Livro para a 47ª Feira do Livro de Porto Alegre. Drummond segurava um livro de bronze, furtado em 2015 e restituído em 2022.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/f3/Monumento_%C3%A0_Literatura_Brasileira_-_Porto_Alegre.jpg/480px-Monumento_%C3%A0_Literatura_Brasileira_-_Porto_Alegre.jpg', 'pt:Monumento à Literatura Brasileira', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'O Túnel do Túnel', -30.0316665, -51.2194685, 'artwork', 'Obra de arte urbana localizada no Centro Histórico de Porto Alegre. A instalação explora de forma lúdica e conceitual a ideia de profundidade e perspectiva, integrando-se à arquitetura e ao cotidiano da cidade. É uma das intervenções artísticas permanentes que compõem o patrimônio cultural público de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'A Fuga', -30.0292514, -51.2313563, 'artwork', 'Escultura pública integrante do Museu de Percurso do Negro em Porto Alegre, projeto cultural que percorre diferentes pontos da cidade com obras de arte que narram a história e a resistência da comunidade afro-brasileira na capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pegada Africana', -30.0301616, -51.2307524, 'artwork', 'Obra de arte pública integrante do Museu de Percurso do Negro em Porto Alegre, iniciativa que espalha esculturas e instalações pela cidade para contar a história e a presença africana e afro-brasileira em Porto Alegre. A peça evoca a chegada e a marca deixada pela cultura africana na formação da sociedade gaúcha.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Teorema', -30.0293408, -51.2319792, 'artwork', 'Escultura pública localizada na Praça da Alfândega, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que ornamentam os espaços públicos centrais da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'A Samaritana', -30.0296353, -51.2304624, 'artwork', 'Escultura pública localizada no Centro Histórico de Porto Alegre. A obra faz referência à figura bíblica da Samaritana, mulher que ofereceu água a Jesus junto a um poço. A peça integra o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'MERGS', -30.030082, -51.2294122, 'museum', 'O Museu da Eletricidade do Rio Grande do Sul (MERGS) está localizado no Centro Histórico de Porto Alegre. Dedicado à história da energia elétrica no estado, o museu preserva equipamentos, documentos e memórias da evolução do sistema elétrico gaúcho, promovendo educação patrimonial e técnica sobre o setor energético.', NULL, 'pt:Museu da Eletricidade do Rio Grande do Sul', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cono Sul', -30.0544285, -51.2307807, 'artwork', 'Escultura pública em forma de cone localizada próxima ao Largo dos Açorianos, em Porto Alegre. A obra integra o conjunto de monumentos que ornamentam os espaços públicos do Centro Histórico, compondo o cenário artístico e cultural da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torre de Ferro', -30.0480886, -51.2325621, 'artwork', 'Escultura vertical em ferro localizada no Centro Histórico de Porto Alegre. A peça integra o conjunto de obras de arte pública que marcam os espaços urbanos da capital gaúcha, estabelecendo diálogo entre arte, arquitetura e paisagem.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pórtico', -30.0481665, -51.231471, 'artwork', 'Escultura em forma de pórtico localizada no Centro Histórico de Porto Alegre. Obras com essa tipologia são comuns no patrimônio artístico público da cidade, funcionando como marcos visuais que delimitam e qualificam espaços urbanos.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0482458, -51.2296503, 'artwork', 'Escultura pública sem título oficial localizada no Centro Histórico de Porto Alegre, próxima ao Largo dos Açorianos. Integra o conjunto de obras de arte permanentes distribuídas pelos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Canhão', -30.0565144, -51.2311506, 'artwork', 'Canhão histórico exposto como peça de patrimônio público no Centro Histórico de Porto Alegre, próximo ao Largo dos Açorianos. Peças de artilharia antigas são frequentemente preservadas como monumentos históricos, evocando o passado militar e colonial da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0527095, -51.2320786, 'artwork', 'Escultura pública sem título oficial localizada no entorno do Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que enriquecem os espaços públicos da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'El Canto de las Flores', -30.0533763, -51.2309029, 'artwork', 'Escultura pública intitulada "El Canto de las Flores" (O Canto das Flores), localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra celebra a natureza e a beleza floral, integrando o patrimônio artístico permanente dos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Flor', -30.0540508, -51.2303814, 'artwork', 'Escultura representando uma flor, localizada próxima ao Largo dos Açorianos no Centro Histórico de Porto Alegre. Obras com temática floral são recorrentes no patrimônio artístico público da cidade, simbolizando vida e renovação urbana.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Mastro', -30.0563759, -51.2310458, 'artwork', 'Mastro decorativo ou escultura vertical localizada próxima ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte pública e elementos urbanos que compõem a paisagem cultural da região central da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Planos em um Plano', -30.0537926, -51.2304328, 'artwork', 'Escultura pública de caráter abstrato localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra explora relações entre planos e volumes no espaço, integrando o conjunto de intervenções artísticas permanentes dos espaços públicos do Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Rayo', -30.0541885, -51.2304854, 'artwork', 'Escultura pública intitulada "Rayo" (Raio), localizada próxima ao Largo dos Açorianos em Porto Alegre. A forma dinâmica da obra evoca energia e movimento, integrando o conjunto de obras de arte permanentes que ornamentam os espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Sem Título', -30.0541129, -51.2306961, 'artwork', 'Escultura pública sem título oficial localizada próxima ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Integra o conjunto de obras de arte permanentes que enriquecem os espaços públicos centrais da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Paisagem Lunar', -30.0272352, -51.1996941, 'artwork', 'Obra de arte pública intitulada "Paisagem Lunar", localizada no bairro Floresta, em Porto Alegre. A escultura ou instalação evoca a superfície da lua, estabelecendo um diálogo poético entre o espaço urbano e o cosmos, integrando o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Âncora', -30.0564948, -51.2310733, 'artwork', 'Âncora histórica exposta como peça de patrimônio público próximo ao Largo dos Açorianos, no Centro Histórico de Porto Alegre. Elementos náuticos como âncoras são frequentemente preservados como monumentos, evocando a história portuária e fluvial da cidade às margens do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cavalo e Cavaleiro', -30.0558338, -51.230855, 'artwork', 'Escultura representando cavalo e cavaleiro, localizada próxima ao Largo dos Açorianos em Porto Alegre. A temática equestre é recorrente no patrimônio artístico gaúcho, remetendo à tradição dos pampas e à figura do gaúcho, símbolo cultural do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Matriz Urbana', -30.0363654, -51.1874249, 'artwork', 'Obra de arte pública intitulada "Matriz Urbana", localizada no bairro Petrópolis, em Porto Alegre. A peça dialoga com os conceitos de estrutura e organização do espaço urbano, integrando o patrimônio artístico público da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Leão de São Marcos', -30.0513786, -51.2294365, 'artwork', 'Escultura representando o Leão de São Marcos, símbolo da República de Veneza, localizada próxima ao Largo dos Açorianos em Porto Alegre. A obra homenageia a herança italiana e veneziana na formação cultural do Rio Grande do Sul, integrando o patrimônio artístico público da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos 100 Anos da Imigração Judaica no RS', -30.0386395, -51.1739162, 'artwork', 'Monumento comemorativo aos 100 anos da imigração judaica no Rio Grande do Sul, localizado no bairro Petrópolis, em Porto Alegre. A obra celebra a contribuição da comunidade judaica para o desenvolvimento cultural, econômico e social do estado gaúcho, reconhecendo a história e a resiliência dos imigrantes e seus descendentes.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria Iberê Camargo', -30.0341205, -51.2414431, 'museum', 'Espaço expositivo vinculado à Fundação Iberê Camargo, dedicado à obra do pintor gaúcho Iberê Camargo (1914–1994), um dos mais importantes artistas plásticos brasileiros do século XX. A Fundação foi criada em 1995 e sua sede atual, projetada pelo arquiteto português Álvaro Siza, foi inaugurada em 2008. O edifício, premiado com o Leão de Ouro na Bienal de Arquitetura de Veneza (2002) e o Mies Crown Hall Americas Prize (2014), é referência arquitetônica internacional. Localizado às margens do Guaíba, é um dos pontos turísticos mais visitados de Porto Alegre.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/7/76/Funda%C3%A7%C3%A3o_Ib%C3%AAr%C3%AA_Camargo.jpg/640px-Funda%C3%A7%C3%A3o_Ib%C3%AAr%C3%AA_Camargo.jpg', 'pt:Fundação Iberê Camargo', 'https://iberecamargo.org.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria dos Arcos', -30.0340932, -51.2413331, 'museum', 'Espaço cultural localizado no entorno da Fundação Iberê Camargo, na Orla do Guaíba, em Porto Alegre. A galeria integra o conjunto de espaços expositivos da região do bairro Cristal, promovendo artes visuais e intervenções culturais em ambiente privilegiado às margens do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria Lunara', -30.033999, -51.2407678, 'museum', 'Espaço cultural localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba, em Porto Alegre. A Galeria Lunara integra o polo cultural da região do bairro Cristal, oferecendo exposições de artes visuais e atividades culturais em um dos pontos mais belos da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'O Peixe', -30.0329613, -51.2193529, 'artwork', 'Escultura pública representando um peixe, localizada no Centro Histórico de Porto Alegre. A obra integra o patrimônio artístico permanente da cidade, estabelecendo vínculo simbólico com o Guaíba e a tradição fluvial da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu de Geologia', -30.0721923, -51.2278539, 'museum', 'O Museu de Geologia de Porto Alegre, vinculado à Companhia de Pesquisa de Recursos Minerais (CPRM), está localizado no bairro Menino Deus. O museu apresenta coleções de rochas, minerais e fósseis representativos da geologia do Brasil e do mundo, com ênfase no patrimônio geológico do Rio Grande do Sul. É um importante espaço de divulgação científica e educação geocientífica.', NULL, 'pt:Museu de Geologia', 'http://www.cprm.gov.br');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria de Arte do DMAE', -30.0271567, -51.2057402, 'museum', 'Espaço cultural do Departamento Municipal de Água e Esgotos (DMAE) de Porto Alegre, dedicado a exposições de artes visuais. A galeria promove a arte local e regional, disponibilizando seus espaços para artistas gaúchos e nacionais, integrando cultura e serviço público na capital gaúcha.', NULL, NULL, 'http://dmaegaleriadearte.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Bará do Mercado', -30.0274752, -51.2278362, 'artwork', 'Obra de arte pública integrante do Museu de Percurso do Negro em Porto Alegre. Bará (ou Exu Bará) é um orixá da tradição afro-brasileira, guardião das encruzilhadas e dos caminhos. A instalação celebra a espiritualidade e a presença da cultura africana no Mercado Público de Porto Alegre, um dos mais tradicionais do Brasil e historicamente frequentado pela comunidade negra da cidade.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Ruy Tedesco', -30.0666284, -51.2364129, 'museum', 'O Museu Engenheiro Ruy Tedesco está localizado no bairro Menino Deus, em Porto Alegre. Preserva a memória e a obra do engenheiro Ruy Tedesco, figura importante para a história da infraestrutura e do desenvolvimento urbano de Porto Alegre e do Rio Grande do Sul. O museu abriga documentos, projetos e objetos relacionados à trajetória profissional e pessoal do homenageado.', NULL, 'pt:Museu Engenheiro Ruy Tedesco', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Canhão', -30.096657, -51.2576215, 'artwork', 'Canhão histórico exposto no bairro Belém Novo, zona sul de Porto Alegre, próximo ao clube náutico da região. Peças de artilharia antigas são frequentemente preservadas como monumentos históricos em espaços públicos, evocando o passado militar e colonial da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Âncora', -30.0973163, -51.2569357, 'artwork', 'Âncora histórica exposta no bairro Belém Novo, zona sul de Porto Alegre, próximo à orla do Guaíba. Elemento náutico preservado como monumento histórico, evoca a tradição de navegação fluvial na região e a história marítima da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Leonel de Moura Brizola', -30.0338114, -51.2303452, 'artwork', 'Estátua em bronze em tamanho natural do ex-governador e político gaúcho Leonel de Moura Brizola (1922–2004), esculpida pelo artista Otto Dumovich. Inaugurada em janeiro de 2014, está localizada entre a Catedral Metropolitana Madre de Deus e o Palácio Piratini, sede do governo do RS. Brizola foi prefeito de Porto Alegre, governador do RS e do RJ, deputado federal e líder do Movimento da Legalidade em 1961, que resistiu ao golpe militar e garantiu a posse do presidente João Goulart.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Painel Afrobrasileiro', -30.0281542, -51.2271656, 'artwork', 'Painel de arte pública integrante do Museu de Percurso do Negro em Porto Alegre. A obra celebra a cultura afro-brasileira e a contribuição dos povos africanos para a formação da identidade cultural gaúcha, integrando a trajetória histórica da comunidade negra em Porto Alegre.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tambor', -30.0325358, -51.2379039, 'artwork', 'Escultura representando um tambor, integrante do Museu de Percurso do Negro em Porto Alegre. O tambor é um instrumento central nas tradições africanas e afro-brasileiras, presente em rituais religiosos, festas e manifestações culturais. A obra celebra a herança rítmica e espiritual da cultura negra na formação de Porto Alegre.', NULL, NULL, 'http://museudepercursodonegroemportoalegre.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Nascente do Arroio das Pedras', -30.0381113, -51.1336505, 'attraction', 'Ponto natural de interesse localizado no bairro Lomba do Pinheiro, em Porto Alegre. A nascente do Arroio das Pedras integra a rede hidrográfica da cidade e representa um espaço de valor ambiental, sendo um dos remanescentes de cursos d''água naturais dentro do perímetro urbano de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Arcos de Ipanema', -30.148616, -51.2254416, 'attraction', 'Formação arquitetônica ou estrutura histórica localizada no bairro Ipanema, zona sul de Porto Alegre, às margens do Guaíba. Os arcos integram o patrimônio histórico e paisagístico da região, próximo à orla que oferece belas vistas do lago Guaíba, especialmente ao entardecer.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'turismo nautico', -30.0187561, -51.2566622, 'attraction', 'Ponto de embarque para passeios de barco pelo Guaíba, o lago que margeia Porto Alegre. Os passeios náuticos permitem contemplar a cidade e os pôr do sol do Guaíba sob uma perspectiva única. O Guaíba é um dos mais famosos pelo pôr do sol do mundo, atraindo turistas do Brasil e do exterior.', NULL, NULL, 'https://www.barcoportoalegre10.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Artsom', -29.9983606, -51.1903255, 'artwork', 'Obra de arte pública intitulada "Artsom", localizada no bairro Sarandi, em Porto Alegre. A obra integra o patrimônio artístico permanente da cidade, presente em espaços públicos do extremo norte da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cow Parade Sindicato', -30.0391616, -51.2202084, 'artwork', 'Escultura de vaca decorada integrante da mostra Cow Parade, evento mundial de arte pública que utiliza vacas em escala real como suporte artístico. As obras são criadas por artistas convidados e distribuídas por espaços públicos da cidade. Esta peça está localizada próxima ao sindicato no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Casa de Cultura Mario Quintana', -30.0311314, -51.2345442, 'museum', 'Centro cultural instalado no histórico prédio do Hotel Majestic (construído entre 1916 e 1933, projeto do arquiteto Theodor Wiederspahn), na Rua dos Andradas, 736. Inaugurada em 25 de setembro de 1990, homenageia o poeta porto-alegrense Mário Quintana (1906–1994), que viveu no apartamento 217 do hotel entre 1968 e 1980. O espaço abriga teatros, cinemas, bibliotecas, galerias, os acervos de Elis Regina e Mário Quintana, café com vista para o Guaíba e jardim no terraço. Primeiro grande edifício de Porto Alegre em concreto armado.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/d/d5/Casa_de_Cultura_Mario_Quintana.jpg/640px-Casa_de_Cultura_Mario_Quintana.jpg', 'pt:Casa de Cultura Mario Quintana', 'https://www.ccmq.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Barco Cisne Branco', -30.0256011, -51.2284628, 'attraction', 'O Barco Cisne Branco é um veleiro histórico que realiza passeios turísticos pelo Guaíba, o lago que banha Porto Alegre. Os passeios oferecem uma experiência única de contemplar a cidade, a orla e os famosos pôr do sol do Guaíba a partir da água. É um dos passeios náuticos mais tradicionais e românticos da capital gaúcha.', NULL, NULL, 'https://www.barcocisnebranco.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Arquivo Histórico', -30.0540425, -51.2016508, 'museum', 'O Arquivo Histórico de Porto Alegre Moysés Vellinho, localizado no bairro Azenha, é a principal instituição de guarda e preservação do patrimônio documental do município de Porto Alegre. Fundado em 1959, reúne documentos históricos desde o século XVIII até os dias atuais, incluindo plantas, fotografias, registros municipais e coleções privadas doadas à cidade. É referência para pesquisadores, historiadores e cidadãos interessados na história de Porto Alegre.', NULL, 'pt:Arquivo Histórico de Porto Alegre Moysés Vellinho', 'http://ahpoa.blogspot.com.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Restinga', -30.165753, -51.1551364, 'artwork', 'Obra de arte pública localizada no bairro Restinga, zona sul de Porto Alegre. O bairro Restinga é uma das maiores comunidades populares do Brasil e a peça integra o patrimônio artístico e cultural da região, valorizando a identidade local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Cavalo de Metal', -30.0354982, -51.1766023, 'artwork', 'Escultura de cavalo em metal localizada no bairro Petrópolis, em Porto Alegre. A figura equestre é símbolo recorrente na cultura gaúcha, evocando os pampas e a tradição pastoril do Rio Grande do Sul. A obra integra o patrimônio artístico permanente da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Garibaldi', -30.0437215, -51.220029, 'attraction', 'Monumento em homenagem a Giuseppe Garibaldi (1807–1882), herói da unificação italiana e figura histórica relevante para o Rio Grande do Sul, onde viveu entre 1837 e 1848 e participou da Revolução Farroupilha. A obra está localizada na Praça Garibaldi, no Centro Histórico de Porto Alegre, reconhecendo a contribuição do "herói de dois mundos" à história gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Gaúcho', -30.0560945, -51.1863552, 'artwork', 'Escultura representando a figura do gaúcho, símbolo cultural do Rio Grande do Sul, localizada no bairro Petrópolis, em Porto Alegre. O gaúcho é o habitante dos pampas sul-rio-grandenses, reconhecido pela sua indumentária típica (pilcha), pelo cavalo, pelo chimarrão e pelas tradições culturais preservadas pelo Movimento Tradicionalista Gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Atlas', -30.0252914, -51.1826331, 'artwork', 'Escultura representando Atlas, o titã da mitologia grega condenado a sustentar o céu sobre os ombros, localizada no bairro Floresta, em Porto Alegre. A figura de Atlas é símbolo de força, resistência e suporte, e a obra integra o patrimônio artístico público da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu das Ilhas', -30.0157427, -51.2609075, 'museum', 'Junto ao CTG Madrugada Campeira (esq. Rua Garruchos)', NULL, NULL, 'https://www.facebook.com/museu-das-ilhas-978206232226945');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Joaquim José Felizardo', -30.0419734, -51.224582, 'museum', 'O Museu de Porto Alegre Joaquim José Felizardo está instalado no Solar Lopo Gonçalves, sobrado histórico construído entre 1845 e 1853 no bairro Cidade Baixa. Fundado em 1979, dedica-se à história e memória de Porto Alegre por meio de três acervos: tridimensional, iconográfico e arqueológico. Homenageia o historiador e criador da Secretaria Municipal de Cultura. O Solar, representativo da arquitetura colonial-neoclássica luso-brasileira, foi tombado como patrimônio histórico em 1979 e é um dos mais belos edifícios históricos da cidade.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/5d/Solar_Lopo_Gon%C3%A7alves.jpg/480px-Solar_Lopo_Gon%C3%A7alves.jpg', 'pt:Museu de Porto Alegre Joaquim Felizardo', 'https://www.museudeportoalegre.com/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Expedicionário', -30.0384007, -51.214857, 'artwork', 'Monumento em granito e bronze inaugurado em 16 de julho de 1957 no Parque Farroupilha, em homenagem aos "pracinhas" da Força Expedicionária Brasileira (FEB) que combateram na Segunda Guerra Mundial (1939–1945). Com 17 metros de altura, foi projetado pelo escultor Antônio Caringi (autor também da Estátua do Laçador) e pelo arquiteto Luiz Carlos de Nascimento e Silva. A ideia partiu de uma campanha do jornal Correio do Povo em 1946. O monumento homenageia os três ramos das forças armadas e inclui a alegoria da Bravura (figura feminina em bronze). Também chamado de Arco da Redenção.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/8/85/Monumento_ao_Expedicion%C3%A1rio_-_Porto_Alegre.jpg/480px-Monumento_ao_Expedicion%C3%A1rio_-_Porto_Alegre.jpg', 'pt:Monumento ao Expedicionário', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Museu Israelita', -30.0325241, -51.2125664, 'museum', 'O Museu Israelita de Porto Alegre está localizado no bairro Bom Fim, região historicamente associada à comunidade judaica da cidade. O museu preserva e divulga a memória, a cultura e a história dos judeus no Rio Grande do Sul, com acervo de objetos rituais, documentos e registros fotográficos da vida comunitária.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Instituto Cultural Judaico Marc Chagal', -30.0324249, -51.2126083, 'museum', 'O Instituto Cultural Judaico Marc Chagall é uma instituição dedicada à preservação e difusão da cultura, história e memória judaica no Rio Grande do Sul. Localizado no bairro Bom Fim, em Porto Alegre, promove exposições, eventos culturais, pesquisas e atividades educativas relacionadas à contribuição judaica para a sociedade gaúcha e brasileira. Homenageia o pintor Marc Chagall (1887–1985), um dos maiores artistas do século XX.', NULL, NULL, 'https://chagall.org.br/');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Travessa dos Venezianos', -30.0421726, -51.222533, 'attraction', 'A Travessa dos Venezianos é um charmoso corredor histórico localizado no bairro Cidade Baixa, em Porto Alegre. O local preserva a memória da comunidade italiana, especialmente dos imigrantes venezianos que se estabeleceram na cidade. A travessa é conhecida por suas fachadas coloridas e atmosfera histórica, sendo um ponto turístico que evoca a herança cultural italiana na capital gaúcha.', NULL, 'pt:Travessa dos Venezianos', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento do Gaúcho Oriental', -30.0371251, -51.2158299, 'artwork', 'Monumento em homenagem ao gaúcho oriental (uruguaio), evocando os laços históricos, culturais e fraternais entre o povo gaúcho do Rio Grande do Sul e o Uruguai. A obra está localizada no Parque Farroupilha, em Porto Alegre, e celebra a identidade compartilhada entre os dois lados da fronteira do Rio da Prata.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Supercuia', -30.0424312, -51.2339418, 'artwork', 'Escultura de grande porte representando uma cuia, o recipiente tradicional utilizado para tomar chimarrão, bebida símbolo da cultura gaúcha. Localizada no bairro Bom Fim, em Porto Alegre, a "Supercuia" é uma obra de arte pública que celebra com humor e monumentalidade um dos ícones mais queridos da identidade cultural do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tributo ao Municipalismo', -30.0494044, -51.2239527, 'artwork', 'Monumento em tributo ao municipalismo, localizado no Centro Histórico de Porto Alegre. A obra celebra a importância do poder local e da autonomia municipal na organização política e social do Brasil, valorizando a democracia e a gestão participativa nas cidades.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Antera', -30.0254791, -51.199585, 'artwork', 'Escultura pública intitulada "Antera", localizada no bairro Floresta, em Porto Alegre. O nome evoca a parte masculina da flor (antera), sugerindo temas de fertilidade, natureza e vida. A obra integra o patrimônio artístico permanente dos espaços públicos da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Loureiro da Silva', -30.0314244, -51.2241482, 'artwork', 'Busto ou estátua em homenagem a José Loureiro da Silva (1905–1959), prefeito de Porto Alegre de 1937 a 1943, responsável pela execução de importantes obras de urbanização na cidade, incluindo a abertura da Avenida Farrapos e outras intervenções que modernizaram a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto San Martín', -30.031875, -51.2231892, 'artwork', 'Busto em homenagem ao General José de San Martín (1778–1850), herói da independência da Argentina, Chile e Peru, considerado o "Libertador da América do Sul". A presença deste monumento em Porto Alegre reflete a relação histórica e cultural entre o Brasil e os países do Prata, celebrando a fraternidade sul-americana.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Tape Porã', -30.0295183, -51.2234433, 'artwork', 'Obra de arte pública cujo nome em guarani significa "Caminho Bonito" ou "Boa Trilha". A peça integra o patrimônio artístico permanente de Porto Alegre e homenageia a cultura indígena guarani, povo que habitava a região antes da colonização europeia. Localizada no Centro Histórico, a obra convida à reflexão sobre as raízes indígenas da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto do General José Gervasio Artigas', -30.0292681, -51.2303854, 'memorial', 'Busto em homenagem ao General José Gervasio Artigas (1764–1850), herói nacional do Uruguai e figura central na história da Bacia do Prata. Artigas lutou pela autonomia dos povos platinos e é símbolo de liberdade e federalismo. O monumento, localizado no Centro Histórico de Porto Alegre, celebra a fraternidade histórica entre o Rio Grande do Sul e o Uruguai.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Conde de Porto Alegre', -30.0318254, -51.2246249, 'monument', 'Monumento em homenagem ao Marechal Manuel Marques de Sousa, Conde de Porto Alegre (1804–1875), militar gaúcho que participou da Guerra do Paraguai, da Revolução Farroupilha e de outros conflitos do Império Brasileiro. O Conde de Porto Alegre é um dos mais importantes personagens militares da história do Rio Grande do Sul e da cidade que leva seu título nobiliárquico.', NULL, 'pt:Monumento ao Conde de Porto Alegre', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a José Loureiro da Silva', -30.0373227, -51.2377061, 'memorial', 'Monumento em homenagem a José Loureiro da Silva (1905–1959), prefeito de Porto Alegre entre 1937 e 1943 (e novamente de 1952 a 1953). Durante sua gestão, foi responsável por importantes obras de urbanização, como a abertura da Avenida Farrapos, a construção do Viaduto Otávio Rocha e a modernização do sistema viário da cidade. Localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Zumbi dos Palmares', -30.0379097, -51.2269822, 'monument', 'Monumento em homenagem a Zumbi dos Palmares (1655–1695), líder do Quilombo dos Palmares, maior reduto de resistência negra da história colonial brasileira, localizado em Alagoas. Zumbi é símbolo de resistência à escravidão e herói nacional afro-brasileiro. O dia 20 de novembro, data de sua morte, é o Dia da Consciência Negra. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Antônio Carlos Lopes', -30.0295366, -51.2314736, 'memorial', 'Herma (busto sobre pilastra) em homenagem a Antônio Carlos Lopes, personalidade ligada à cultura e à imprensa porto-alegrense. Localizada no Centro Histórico de Porto Alegre, a peça integra o conjunto de homenagens a personagens relevantes da história da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Caldas Júnior', -30.030248, -51.231177, 'memorial', 'Herma em homenagem a Caldas Júnior (1868–1913), fundador do Correio do Povo, o mais antigo jornal em circulação no Rio Grande do Sul, fundado em 1895. Caldas Júnior foi uma figura central para a imprensa gaúcha e para a vida cultural de Porto Alegre no início do século XX. A herma está localizada no Centro Histórico da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma a Francisco de Leonardo Truda', -30.0299934, -51.2304567, 'memorial', 'Herma em homenagem a Francisco de Leonardo Truda (1878–1942), jornalista, escritor e intelectual gaúcho que exerceu grande influência na vida cultural e política do Rio Grande do Sul no início do século XX. Truda foi diretor do Correio do Povo e colaborou com diversas publicações da época.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Herma ao Barão de Santo Ângelo', -30.0300469, -51.2310464, 'memorial', 'Herma em homenagem ao Barão de Santo Ângelo, título nobiliárquico do Império Brasileiro relacionado à cidade de Santo Ângelo, no Rio Grande do Sul. O monumento está localizado no Centro Histórico de Porto Alegre e integra o conjunto de homenagens a figuras históricas relevantes para o estado gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a José Bertaso', -30.0301308, -51.2308168, 'memorial', 'Monumento em homenagem a José Bertaso, empresário e fundador da Livraria do Globo, uma das mais importantes editoras e livrarias da história cultural do Rio Grande do Sul. A Livraria do Globo, fundada em Porto Alegre no final do século XIX, publicou obras de grandes escritores brasileiros e foi um centro cultural fundamental para o Sul do Brasil.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de João Cândido', -30.0516709, -51.2300329, 'memorial', 'Busto em homenagem a João Cândido Felisberto (1880–1969), o "Almirante Negro", líder da Revolta da Chibata de 1910, movimento que aboliu os castigos corporais na Marinha Brasileira. João Cândido nasceu em Santo Antônio da Patrulha (RS) e é símbolo da resistência negra no Brasil. O busto está localizado próximo ao Largo dos Açorianos, no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto do Almirante Marquês de Tamandaré', -30.0565145, -51.2310993, 'memorial', 'Busto em homenagem ao Almirante Joaquim Marques Lisboa, Marquês de Tamandaré (1807–1897), patrono da Marinha Brasileira e um dos maiores heróis navais da história do Brasil. Natural de Rio Grande (RS), Tamandaré participou de diversas batalhas navais, incluindo a Guerra do Paraguai. O busto está localizado próximo ao Largo dos Açorianos.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Plácido de Castro', -30.0566813, -51.2317952, 'memorial', 'Monumento em homenagem a José Plácido de Castro (1873–1908), militar gaúcho que liderou a Revolução Acreana (1902–1903), movimento que resultou na incorporação do Acre ao território brasileiro. Plácido de Castro é herói nacional e símbolo do expansionismo territorial brasileiro. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torre de Ferro', -30.0480886, -51.2325621, 'artwork', 'Escultura vertical em ferro localizada no Centro Histórico de Porto Alegre. A peça integra o conjunto de obras de arte pública que marcam os espaços urbanos da capital gaúcha, estabelecendo diálogo entre arte, arquitetura e paisagem.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Manoel Raimundo Soares', -30.0503832, -51.2323, 'memorial', 'Monumento em homenagem a Manoel Raimundo Soares (1939–1966), militante político gaúcho assassinado durante a ditadura militar brasileira (1964–1985). Soares foi preso, torturado e morto pelos agentes do regime. Seu corpo, com as mãos atadas, foi encontrado boiando no Rio Jacuí, sendo chamado de "O Anjo das Pernas Tortas". O monumento está localizado no Centro Histórico de Porto Alegre e é um símbolo da resistência democrática.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Centenário da Imigração Judaica', -30.0359385, -51.2110474, 'monument', 'Monumento comemorativo ao centenário da imigração judaica no Rio Grande do Sul, localizado no bairro Bom Fim, em Porto Alegre. A obra celebra a chegada dos primeiros imigrantes judeus ao estado, sua contribuição para o desenvolvimento econômico, cultural e social do RS e a formação de uma das mais expressivas comunidades judaicas do Brasil.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Santos Dumont', -30.0381602, -51.2149518, 'memorial', 'Memorial ou busto em homenagem a Alberto Santos Dumont (1873–1932), inventor brasileiro considerado por muitos o "Pai da Aviação". Santos Dumont realizou o histórico voo do 14-Bis em Paris, em 1906, e é patrono da Aeronáutica Brasileira. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Marco da Carris', -30.0347311, -51.2220535, 'monument', 'Marco histórico em homenagem à CARRIS (Companhia Carris Porto-Alegrense), empresa responsável pelo transporte público de bondes e ônibus em Porto Alegre. Os bondes elétricos circularam pela cidade de 1908 a 1970, sendo um dos sistemas de transporte mais importantes da história urbana da capital gaúcha. O marco está localizado no Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Lions Clube Balneários', -30.1040315, -51.2530188, 'memorial', 'Monumento doado pelo Lions Clube Balneários à cidade de Porto Alegre, localizado na zona sul da capital. O Lions Club International é uma organização humanitária mundial dedicada ao serviço comunitário, e os monumentos doados pelos clubes locais marcam o compromisso com a comunidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Ano Internacional da Criança', -30.0278356, -51.201574, 'memorial', 'Monumento em comemoração ao Ano Internacional da Criança, proclamado pela ONU em 1979, que marcou o 20º aniversário da Declaração dos Direitos da Criança. A obra está localizada no bairro Floresta, em Porto Alegre, e celebra os direitos, a proteção e o bem-estar das crianças.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Lions Clube Independência', -30.0278679, -51.2003229, 'memorial', 'Monumento doado pelo Lions Clube Independência à cidade de Porto Alegre. Localizado no bairro Floresta, o monumento marca a contribuição da filial local do Lions Club International às ações comunitárias e humanitárias na capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Johann Wolfgang von Goethe', -30.0283958, -51.2003725, 'memorial', 'Monumento em homenagem a Johann Wolfgang von Goethe (1749–1832), o maior escritor da língua alemã e um dos maiores da literatura universal. Autor do "Fausto" e de "Os Sofrimentos do Jovem Werther", Goethe exerceu influência profunda na cultura ocidental. O monumento está localizado no bairro Floresta, em Porto Alegre, e homenageia a forte herança cultural alemã no Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Rotary Club', -30.0282175, -51.2008042, 'memorial', 'Monumento doado pelo Rotary Club à cidade de Porto Alegre, localizado no bairro Floresta. O Rotary International é uma das maiores organizações humanitárias do mundo, e este monumento marca a presença e a contribuição do clube local às ações comunitárias da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Maurício Sirotsky Sobrinho', -30.0397023, -51.237552, 'memorial', 'Busto em homenagem a Maurício Sirotsky Sobrinho (1931–1990), empresário gaúcho e fundador do Grupo RBS (Rede Brasil Sul de Comunicações), maior conglomerado de mídia do Sul do Brasil. Sirotsky foi uma figura central para o desenvolvimento da comunicação e da cultura no Rio Grande do Sul. O busto está localizado próximo à Orla do Guaíba.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a José Antônio Daudt', -30.0266226, -51.2013906, 'memorial', 'Memorial em homenagem a José Antônio Daudt, personalidade ligada à história política e administrativa de Porto Alegre. O memorial está localizado no bairro Floresta, integrando o conjunto de homenagens a personagens relevantes da história da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Rotary Club de Porto Alegre Norte', -30.0251712, -51.2012585, 'memorial', 'Memorial em homenagem ao Rotary Club de Porto Alegre Norte, reconhecendo a atuação humanitária e comunitária do clube na região norte da capital gaúcha. Localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Taxistas Mortos em Serviço', -30.0423798, -51.2333608, 'memorial', 'Memorial em homenagem aos taxistas que perderam a vida em serviço na cidade de Porto Alegre. A obra presta tributo aos profissionais do transporte individual que foram vítimas de violência ou acidentes no exercício de sua profissão, reconhecendo os riscos enfrentados cotidianamente por esses trabalhadores.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pedra da Memória', -30.0396429, -51.2378081, 'memorial', 'Memorial em forma de pedra localizado próximo à Orla do Guaíba, em Porto Alegre. A "Pedra da Memória" é um espaço de recordação e homenagem a pessoas ou eventos, integrando o patrimônio memorialístico da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento Gaúcho Oriental', -30.0348541, -51.2206334, 'monument', 'Monumento em homenagem ao gaúcho oriental (uruguaio), celebrando os laços históricos e culturais entre o povo gaúcho do Rio Grande do Sul e o Uruguai. A obra está localizada no Centro Histórico de Porto Alegre e evoca a identidade compartilhada entre as duas margens do Rio da Prata.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Centenário de Nascimento do Deputado Carlos Santos', -30.0436946, -51.2042676, 'memorial', 'Memorial comemorativo ao centenário de nascimento do Deputado Carlos Santos, político gaúcho que teve atuação relevante na história legislativa do Rio Grande do Sul. O memorial está localizado no bairro Azenha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao PM Valdeci de Abreu Lopes', -30.0428553, -51.2042113, 'memorial', 'Memorial em homenagem ao policial militar Valdeci de Abreu Lopes, morto em serviço na cidade de Porto Alegre. O memorial presta tributo ao sacrifício dos agentes de segurança pública que perderam a vida no cumprimento do dever de proteger a comunidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Rotary Club de Porto Alegre Norte', -30.0294291, -51.2008077, 'monument', 'Monumento doado pelo Rotary Club de Porto Alegre Norte à cidade, reconhecendo a atuação humanitária e comunitária da organização na região norte da capital gaúcha. Localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Coluna Israelita', -30.0336457, -51.2160712, 'monument', 'Coluna comemorativa da comunidade judaica de Porto Alegre, localizada no bairro Bom Fim, região historicamente associada à comunidade israelita da cidade. A coluna homenageia a contribuição dos imigrantes judeus e seus descendentes para o desenvolvimento cultural, econômico e social de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Carlos Gomes', -30.0350054, -51.2140092, 'monument', 'Busto em homenagem a Antônio Carlos Gomes (1836–1896), compositor brasileiro considerado o maior ópera do século XIX nas Américas. Sua obra mais famosa, "O Guarani" (1870), foi apresentada com grande sucesso no Teatro alla Scala de Milão. O busto está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto de Chopin', -30.0347287, -51.2139578, 'monument', 'Busto em homenagem a Frédéric Chopin (1810–1849), pianista e compositor polonês, um dos maiores músicos românticos da história. Suas obras para piano solo são consideradas entre as mais expressivas da literatura musical. O busto está localizado no Parque Farroupilha, em Porto Alegre, integrando o conjunto de homenagens a músicos universais presentes no parque.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Beethoven', -30.0347697, -51.213872, 'monument', 'Monumento em homenagem a Ludwig van Beethoven (1770–1827), compositor alemão considerado um dos maiores gênios da história da música ocidental. Suas nove sinfonias, seus concertos para piano e suas sonatas são obras-primas da humanidade. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Obelisco à Comunidade Sírio-Libanesa', -30.0354607, -51.2177687, 'monument', 'Obelisco em homenagem à comunidade sírio-libanesa de Porto Alegre, localizado no Parque Farroupilha. A imigração síria e libanesa para o Rio Grande do Sul, iniciada no final do século XIX, trouxe importantes contribuições para o comércio, a cultura e a gastronomia da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Imperatriz Leopoldina', -30.0347791, -51.220929, 'monument', 'Monumento em homenagem à Imperatriz Maria Leopoldina da Áustria (1797–1826), primeira imperatriz do Brasil e esposa de Dom Pedro I. Leopoldina desempenhou papel fundamental na Independência do Brasil em 1822, sendo uma das mais importantes figuras femininas da história brasileira. O monumento está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torii', -30.0356375, -51.2157841, 'monument', 'Torii é um portão tradicional japonês que marca a entrada de um santuário xintoísta. O torii presente no Parque Farroupilha, em Porto Alegre, foi doado pela comunidade japonesa e homenageia a imigração nipônica no Rio Grande do Sul. É um símbolo da diversidade cultural que caracteriza a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Fundadores do Veleiros do Sul', -30.0966733, -51.2575772, 'memorial', 'Memorial em homenagem aos fundadores do Veleiros do Sul, clube náutico localizado no bairro Belém Novo, zona sul de Porto Alegre, às margens do Guaíba. O clube é uma das mais tradicionais associações de vela do Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Comodoro Jorge Bertschinger', -30.0969104, -51.2568917, 'memorial', 'Monumento em homenagem ao Comodoro Jorge Bertschinger, personalidade relevante para o esporte náutico e a história do iatismo no Rio Grande do Sul. O memorial está localizado no bairro Belém Novo, próximo ao Veleiros do Sul, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Tamandaré', -30.0955567, -51.2562098, 'memorial', 'Monumento em homenagem ao Almirante Joaquim Marques Lisboa, Marquês de Tamandaré (1807–1897), patrono da Marinha Brasileira. Natural de Rio Grande (RS), Tamandaré é o maior herói naval da história brasileira, tendo participado de batalhas na Guerra do Paraguai e outros conflitos. O monumento está localizado no bairro Belém Novo, próximo à marina local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem à Imigração Alemã no Brasil', -30.0237338, -51.1565299, 'memorial', 'Memorial em homenagem à imigração alemã no Brasil, localizado no bairro Sarandi, em Porto Alegre. Os imigrantes alemães chegaram ao Rio Grande do Sul a partir de 1824, sendo São Leopoldo (RS) o primeiro polo de colonização germânica. A imigração alemã moldou profundamente a cultura, a arquitetura, a gastronomia e a economia do estado gaúcho.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Estátua de Fernandão', -30.0669412, -51.2364426, 'memorial', 'Estátua em homenagem a Fernando Luís Rosa, o "Fernandão" (1978–2014), atacante gaúcho que jogou no Grêmio e na seleção brasileira. Considerado ídolo do clube tricolor, Fernandão faleceu tragicamente em um acidente de helicóptero. A estátua está localizada próxima ao Estádio Olímpico Monumental, no bairro Menino Deus.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem ao Almirante Tamandaré', -30.0416282, -51.1824233, 'memorial', 'Memorial em homenagem ao Almirante Tamandaré, patrono da Marinha Brasileira, localizado no bairro Petrópolis, em Porto Alegre. A homenagem reconhece a importância de Tamandaré para a história naval do Brasil e seu legado como figura exemplar das Forças Armadas brasileiras.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial Empresa de Onibus Belem', -30.2098055, -51.1883893, 'memorial', 'Memorial da Empresa de Ônibus Belém, localizado no bairro Belém Novo, zona sul de Porto Alegre. O memorial preserva a história e a tradição da viação Belém, uma das transportadoras de passageiros que contribuiu para a mobilidade urbana na região sul da capital gaúcha.', NULL, NULL, 'http://www.viacaobelemnovo.com.br');
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Grêmio FBPA', -30.0286543, -51.2006294, 'monument', 'Monumento em homenagem ao Grêmio Foot-Ball Porto Alegrense (GBPA), fundado em 15 de setembro de 1903, um dos maiores clubes de futebol do Brasil. O Grêmio é tricampeão mundial (1983, 1983 Intercontinental e Copa Libertadores múltiplas vezes) e ídolo da torcida gaúcha. O monumento está localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial Olímpico', -30.0092693, -51.1883565, 'memorial', 'O Memorial Olímpico de Porto Alegre está localizado no bairro Sarandi e homenageia os atletas gaúchos que representaram o Brasil nos Jogos Olímpicos. O Rio Grande do Sul tem uma longa tradição esportiva olímpica, com atletas de destaque em diversas modalidades. O memorial celebra o esforço, a dedicação e as conquistas dos esportistas gaúchos no cenário internacional.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Panteão dos Laureados', -30.0094113, -51.1881564, 'memorial', 'O Panteão dos Laureados, localizado no bairro Sarandi, em Porto Alegre, presta homenagem aos atletas gaúchos que conquistaram medalhas em competições olímpicas e internacionais. O espaço integra o conjunto de memórias esportivas da capital gaúcha e celebra as conquistas dos esportistas do Rio Grande do Sul no cenário mundial.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a João Goulart', -30.0365573, -51.240995, 'memorial', 'Memorial em homenagem a João Goulart (1919–1976), o "Jango", presidente do Brasil de 1961 a 1964 e figura central da história política gaúcha. Goulart foi deposto pelo golpe militar de 1964 e viveu no exílio até a abertura política. Natural de São Borja (RS), é símbolo do trabalhismo e da democracia no Brasil. O memorial está localizado próximo à Orla do Guaíba, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Duque de Caxias', -30.0381971, -51.2150185, 'memorial', 'Memorial ou busto em homenagem ao Marechal Luís Alves de Lima e Silva, Duque de Caxias (1803–1880), patrono do Exército Brasileiro e considerado o maior herói militar da história do Brasil. Caxias participou de diversas guerras e pacificações, sendo símbolo de lealdade e bravura. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Almirante Tamandaré', -30.0382411, -51.2150922, 'memorial', 'Memorial em homenagem ao Almirante Tamandaré, patrono da Marinha Brasileira, localizado no Parque Farroupilha, em Porto Alegre. Natural de Rio Grande (RS), o Marquês de Tamandaré é o maior herói naval do Brasil, símbolo de coragem e patriotismo das Forças Armadas brasileiras.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Povo Cigano', -30.0282668, -51.2004831, 'memorial', 'Memorial em homenagem ao Povo Cigano, localizado no bairro Floresta, em Porto Alegre. A obra reconhece a presença e a contribuição da comunidade cigana na formação cultural do Brasil e do Rio Grande do Sul, celebrando a diversidade étnica e cultural da nação.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Mosaico Rosa dos Ventos', -29.9910528, -51.1843292, 'memorial', 'Mosaico em forma de rosa dos ventos localizado no bairro Sarandi, em Porto Alegre. A rosa dos ventos é símbolo de orientação e navegação, evocando os quatro pontos cardeais. O mosaico integra o patrimônio artístico público da região norte da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Pórtico da UFRGS Campus do Vale', -30.0762526, -51.1248862, 'monument', 'Pórtico de entrada do Campus do Vale da Universidade Federal do Rio Grande do Sul (UFRGS), localizado no bairro Agronomia. A UFRGS é a maior e mais importante universidade federal do Sul do Brasil, fundada em 1895. O Campus do Vale abriga institutos de ciências exatas, biológicas e tecnológicas, além de importantes museus universitários. O pórtico marca a entrada principal do campus.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem aos Servidores Municipais', -30.0346915, -51.2413474, 'memorial', 'Memorial em homenagem aos servidores municipais de Porto Alegre, localizado próximo à Fundação Iberê Camargo, na Orla do Guaíba. A obra reconhece a dedicação e o trabalho dos funcionários públicos municipais que contribuem para o funcionamento e o desenvolvimento da capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Bonde', -30.0415008, -51.2235705, 'memorial', 'Memorial preservando um bonde histórico, evocando a era dos bondes elétricos em Porto Alegre, que circularam pela cidade de 1908 a 1970. Os bondes foram o principal meio de transporte coletivo da capital gaúcha por décadas, e sua memória é preservada como patrimônio cultural da cidade. O memorial está localizado no Centro Histórico.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Escultura de Pedro Rocha', -30.0294116, -51.2013109, 'monument', 'Escultura em homenagem a Pedro Rocha, ex-jogador do Grêmio. Autores: Mario Cladera e Vinicius Vieira.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Símbolo da luta contra a violência no trânsito', -30.0609262, -51.2106216, 'monument', 'Monumento simbólico de conscientização sobre a violência no trânsito, localizado no bairro Menino Deus, em Porto Alegre. A obra integra as ações de educação para o trânsito da cidade, alertando para os riscos da imprudência nas ruas e prestando homenagem às vítimas de acidentes.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'super tinga', -30.1531856, -51.1358503, 'monument', 'Monumento em homenagem a Tinga, nome popular de Célio Fernando Soares Rodrigues, ídolo do futebol gaúcho. Localizado no bairro Belém Novo, na zona sul de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento a Garibaldi', -30.0437215, -51.220029, 'attraction', 'Monumento em homenagem a Giuseppe Garibaldi (1807–1882), herói da unificação italiana e figura histórica relevante para o Rio Grande do Sul, onde viveu entre 1837 e 1848 e participou da Revolução Farroupilha. Localizado na Praça Garibaldi, no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Busto Júlio de Castilhos', -30.0287979, -51.2083878, 'memorial', 'Busto em homenagem a Júlio Prates de Castilhos (1860–1903), político positivista gaúcho que foi presidente do Rio Grande do Sul de 1893 a 1898. Castilhos foi figura central na consolidação da República no RS e foi o grande mentor de Borges de Medeiros. O bairro Júlio de Castilhos e o Museu Júlio de Castilhos levam seu nome. O busto está localizado no bairro Floresta, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Fernando Chagas Riet', -30.0561634, -51.2223142, 'memorial', 'Memorial em homenagem a Fernando Chagas Riet, personalidade ligada à história do esporte ou da cultura em Porto Alegre. O memorial está localizado no bairro Cidade Baixa, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Marechal Mascarenhas de Moraes', -30.0381144, -51.2148254, 'memorial', 'Memorial em homenagem ao Marechal João Batista Mascarenhas de Moraes (1883–1968), comandante da Força Expedicionária Brasileira (FEB) na Segunda Guerra Mundial, na campanha da Itália (1944–1945). Natural de Passo Fundo (RS), Mascarenhas de Moraes é um dos maiores heróis militares gaúchos. O memorial está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Dr. José Faibes Lubianca', -30.0363591, -51.2103382, 'memorial', 'Memorial em homenagem ao Dr. José Faibes Lubianca, médico e personalidade relevante para a história da saúde pública em Porto Alegre. O memorial está localizado no bairro Bom Fim, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Oswaldo Vergara', -30.0325184, -51.2298651, 'memorial', 'Memorial em homenagem a Oswaldo Vergara (1886–1975), advogado, político e figura proeminente da vida pública gaúcha. Vergara foi presidente do Partido Trabalhista Brasileiro (PTB) no RS e colaborador próximo de Getúlio Vargas. O memorial está localizado no Centro Histórico de Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Professor André Leão Puente', -30.0329268, -51.2298377, 'memorial', 'Memorial em homenagem ao Professor André Leão Puente, educador relevante na história da instrução pública em Porto Alegre. O memorial está localizado no Centro Histórico da cidade, reconhecendo a contribuição do homenageado para a educação gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Desiderio Finamor', -30.0569388, -51.2224875, 'memorial', 'Memorial em homenagem a Desiderio Finamor, personalidade ligada à história política ou cultural de Porto Alegre. O memorial está localizado no bairro Cidade Baixa.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'DC-3', -29.9957118, -51.1868187, 'memorial', 'Aeronave histórica Douglas DC-3, preservada como memorial no bairro Sarandi, em Porto Alegre. O DC-3 foi um dos aviões mais importantes da história da aviação civil e militar mundial, produzido entre 1936 e 1942. Muitos exemplares serviram no Brasil, inclusive no Rio Grande do Sul. A aeronave exposta é um símbolo do desenvolvimento da aviação nacional.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Imagem religiosa', -30.1910421, -51.0368067, 'monument', 'Imagem religiosa localizada na zona rural de Porto Alegre, próxima ao bairro Lami. Capelas e imagens de santos são comuns na paisagem rural gaúcha, marcando a devoção religiosa das comunidades de origem europeia que colonizaram a região.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento ao Batalhão Suez', -30.038453, -51.2300938, 'monument', 'Monumento inaugurado em 8 de janeiro de 2016 na Praça dos Açorianos, em homenagem aos soldados gaúchos que integraram o Batalhão Suez, participando das missões de paz da ONU no Oriente Médio entre 1957 e 1967. O Brasil enviou 20 contingentes do Exército ao Canal de Suez, compondo a Força de Emergência das Nações Unidas (UNEF I). A estrutura piramidal em granito, com globo e capacete azul no topo, homenageia os cerca de 700 gaúchos do 5º, 13º e 20º contingentes.', 'https://upload.wikimedia.org/wikipedia/commons/thumb/5/57/Monumento_ao_Batalhao_Suez_-_Porto_Alegre.jpg/480px-Monumento_ao_Batalhao_Suez_-_Porto_Alegre.jpg', 'pt:Monumento ao Batalhão Suez', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Monumento aos Açorianos', -30.0390289, -51.2295676, 'monument', 'Monumento inaugurado em 26 de março de 1974, aniversário de Porto Alegre, em homenagem à chegada dos primeiros 60 casais açorianos que fundaram a cidade em 1752. A obra do escultor Carlos Tenius, com 17 m de altura e 24 m de comprimento, é feita em aço e evoca uma caravela composta de corpos humanos entrelaçados, tendo à frente uma figura alada (inspirada em Ícaro) que representa a vitória. Localizada no Largo dos Açorianos, próximo ao Centro Administrativo do Estado. Restaurada entre 2016 e 2019.', 'https://upload.wikimedia.org/wikipedia/commons/2/29/Largo_dos_a%C3%A7orianos_2.jpg', 'pt:Monumento aos Açorianos', NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Torii', -30.03567, -51.2157882, 'monument', 'Torii é um portão tradicional japonês que marca a entrada de um santuário xintoísta. O torii presente no Parque Farroupilha, em Porto Alegre, foi doado pela comunidade japonesa e homenageia a imigração nipônica no Rio Grande do Sul. É um símbolo da diversidade cultural que caracteriza a capital gaúcha.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Nicolau Copérnico', -30.0438357, -51.2076519, 'memorial', 'Memorial em homenagem a Nicolau Copérnico (1473–1543), astrônomo polonês que formulou o modelo heliocêntrico do Sistema Solar, revolucionando a astronomia e o pensamento científico. O monumento está localizado no bairro Azenha, em Porto Alegre, e homenageia a herança cultural polonesa no Rio Grande do Sul.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Annes Dias', -30.0368893, -51.2193317, 'monument', 'Monumento em homenagem ao Dr. Annes Dias (1875–1941), médico sanitarista gaúcho de grande importância para a saúde pública no Rio Grande do Sul e no Brasil. Annes Dias combateu doenças como a varíola e outras endemias, contribuindo decisivamente para a melhoria das condições sanitárias da população gaúcha no início do século XX.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Samuel Hahnemann', -30.0378556, -51.2185464, 'monument', 'Monumento em homenagem a Samuel Hahnemann (1755–1843), médico alemão fundador da homeopatia. A homeopatia foi amplamente difundida no Rio Grande do Sul por imigrantes alemães no século XIX. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Homenagem a Licino Cardoso', -30.0372338, -51.2190873, 'monument', 'Monumento em homenagem a Licínio Cardoso, intelectual e filósofo brasileiro do início do século XX, expoente do positivismo no Brasil. O Positivismo de Auguste Comte foi fortemente influente no Rio Grande do Sul, moldando a política e a cultura gaúcha na Primeira República. O monumento está localizado no Parque Farroupilha, em Porto Alegre.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Memorial às Vítimas da COVID-19', -30.0560132, -51.2313612, 'memorial', 'Memorial em homenagem às vítimas da pandemia de COVID-19 em Porto Alegre. Inaugurado após a crise sanitária que assolou o Brasil e o mundo a partir de 2020, o memorial preserva a memória dos que perderam a vida para a doença e homenageia os profissionais de saúde que lutaram para salvar vidas. Localizado no Centro Histórico da cidade.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Padre Paulo de Nadal', -30.0483596, -51.2171512, 'memorial', 'Memorial em homenagem ao Padre Paulo de Nadal, religioso que teve atuação relevante na vida comunitária e social de Porto Alegre. O memorial está localizado no bairro Cidade Baixa, reconhecendo a contribuição do sacerdote para a comunidade local.', NULL, NULL, NULL);
INSERT INTO places (id, name, lat, lon, type, description, image, wikipedia, website) VALUES (gen_random_uuid(), 'Galeria de Arte do DMAE', -30.0271567, -51.2057402, 'museum', 'Espaço cultural do Departamento Municipal de Água e Esgotos (DMAE) de Porto Alegre, dedicado a exposições de artes visuais. A galeria promove a arte local e regional, disponibilizando seus espaços para artistas gaúchos e nacionais, integrando cultura e serviço público na capital gaúcha.', NULL, NULL, 'http://dmaegaleriadearte.blogspot.com.br/');
